{
  "name": "FixItNow - Professional Maintenance Finder",
  "description": "A premium platform to find and contact professional maintenance workers in any city. Includes AI-powered problem diagnosis and integrated maps.",
  "requestFramePermissions": [
    "geolocation"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface MaintenanceWorker {
  id: string;
  name: string;
  category: string;
  rating: number;
  reviews: number;
  experience: string;
  hourlyRate: number;
  status: 'online' | 'busy' | 'offline';
  location: {
    lat: number;
    lng: number;
    address: string;
  };
  phone: string;
  avatar: string;
  skills: string[];
}

export interface Category {
  id: string;
  name: string;
  icon: string;
  description: string;
}

export interface Message {
  role: 'user' | 'assistant';
  content: string;
}

import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const diagnoseIssue = async (userInput: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `L'utilisateur a le problème suivant : "${userInput}". 
      En tant qu'assistant de maintenance professionnel pour un étranger dans une nouvelle ville, 
      identifie la catégorie de maintenance appropriée (parmi : plumbing, electrical, hvac, appliance, locksmith, general) 
      et donne un court conseil de sécurité ou une explication simple de ce qui pourrait être cassé.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            category: {
              type: Type.STRING,
              description: "La clé de la catégorie (ex: plumbing)",
            },
            explanation: {
              type: Type.STRING,
              description: "Explication courte et rassurante.",
            },
            urgency: {
              type: Type.STRING,
              description: "Niveau d'urgence: Bas, Moyen, Haut",
            }
          },
          required: ["category", "explanation", "urgency"]
        },
      },
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

import React, { useState, useMemo } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue } from './services/geminiService';

const App: React.FC = () => {
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');

  const filteredWorkers = useMemo(() => {
    return MOCK_WORKERS.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery]);

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (error) {
      console.error("Diagnosis failed", error);
    } finally {
      setAiLoading(false);
    }
  };

  const getUrgencyColor = (urgency: string) => {
    const u = urgency.toLowerCase();
    if (u.includes('haut') || u.includes('high')) return 'text-red-600 bg-red-50 border-red-100';
    if (u.includes('moyen') || u.includes('medium')) return 'text-amber-600 bg-amber-50 border-amber-100';
    return 'text-emerald-600 bg-emerald-50 border-emerald-100';
  };

  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-indigo-100 selection:text-indigo-900">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={resetFilters}>
            <div className="w-10 h-10 bg-indigo-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
              <i className="fas fa-tools text-xl"></i>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">FixIt<span className="text-indigo-600">Now</span></h1>
          </div>
          <nav className="hidden md:flex items-center gap-8">
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-indigo-600 transition-colors">Accueil</a>
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-indigo-600 transition-colors">Services</a>
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-indigo-600 transition-colors">Aide</a>
            <button className="bg-slate-900 text-white px-5 py-2.5 rounded-full text-sm font-bold hover:bg-slate-800 transition-all shadow-md active:scale-95">
              Devenir Pro
            </button>
          </nav>
          <button className="md:hidden text-slate-500">
            <i className="fas fa-bars text-xl"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-8 md:py-12">
        {/* Hero & Search Section */}
        <section className="mb-12 text-center md:text-left">
          <div className="max-w-3xl">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 mb-6 leading-[1.15]">
              Un pépin technique ? <br/>
              <span className="text-indigo-600">On s'occupe de tout.</span>
            </h2>
            <p className="text-lg text-slate-600 mb-10 max-w-xl">
              Nouveau en ville ? Ne paniquez pas. Décrivez votre problème et notre IA identifiera l'expert idéal pour vous aider immédiatement.
            </p>

            <div className="relative group max-w-2xl">
              <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                <i className="fas fa-wand-magic-sparkles text-slate-400 group-focus-within:text-indigo-500 transition-colors"></i>
              </div>
              <input 
                type="text" 
                placeholder="Ex: Mon évier est bouché et l'eau déborde..."
                className="block w-full pl-14 pr-36 py-5 bg-white border border-slate-200 rounded-2xl shadow-xl shadow-slate-200/50 focus:ring-4 focus:ring-indigo-500/10 focus:border-indigo-500 transition-all text-slate-900 placeholder:text-slate-400 outline-none text-lg"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAiDiagnose()}
              />
              <button 
                onClick={handleAiDiagnose}
                disabled={aiLoading}
                className="absolute right-2.5 top-2.5 bottom-2.5 bg-indigo-600 text-white px-8 rounded-xl font-bold hover:bg-indigo-700 active:scale-95 transition-all disabled:opacity-50 flex items-center gap-2 shadow-lg shadow-indigo-200"
              >
                {aiLoading ? <i className="fas fa-circle-notch animate-spin"></i> : <i className="fas fa-bolt"></i>}
                <span>Analyser</span>
              </button>
            </div>
          </div>
        </section>

        {/* AI Result Banner */}
        {aiResult && (
          <div className="mb-12 p-8 bg-white border border-indigo-100 rounded-3xl shadow-xl shadow-indigo-100/20 animate-in fade-in slide-in-from-bottom-4 duration-500 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-5">
              <i className="fas fa-robot text-9xl"></i>
            </div>
            <div className="flex flex-col md:flex-row items-start gap-6 relative z-10">
              <div className="w-14 h-14 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-indigo-200">
                <i className="fas fa-brain text-2xl"></i>
              </div>
              <div className="flex-1">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
                  <h3 className="text-xl font-bold text-slate-900">Diagnostic de l'IA FixIt</h3>
                  <div className="flex gap-2">
                    <span className={`px-4 py-1.5 rounded-full text-xs font-bold border ${getUrgencyColor(aiResult.urgency)}`}>
                      <i className="fas fa-clock mr-2"></i>Urgence: {aiResult.urgency}
                    </span>
                    <button onClick={() => setAiResult(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                      <i className="fas fa-times"></i>
                    </button>
                  </div>
                </div>
                <p className="text-slate-600 text-lg leading-relaxed mb-6">
                  {aiResult.explanation}
                </p>
                <div className="flex flex-wrap gap-3">
                  <div className="bg-indigo-50 text-indigo-700 px-4 py-2 rounded-xl text-sm font-semibold flex items-center gap-2 border border-indigo-100">
                    <i className="fas fa-check-circle"></i>
                    Catégorie recommandée : {CATEGORIES.find(c => c.id === aiResult.category)?.name || aiResult.category}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Filters & View Toggle */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-8">
          <div className="flex items-center gap-2 overflow-x-auto pb-2 w-full md:w-auto no-scrollbar">
            <button 
              onClick={() => setSelectedCategory(null)}
              className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold transition-all ${!selectedCategory ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-indigo-300'}`}
            >
              Tous
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id}
                onClick={() => setSelectedCategory(cat.id)}
                className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold flex items-center gap-2 transition-all ${selectedCategory === cat.id ? 'bg-indigo-600 text-white shadow-lg shadow-indigo-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-indigo-300'}`}
              >
                <i className={`fas ${cat.icon}`}></i>
                {cat.name}
              </button>
            ))}
          </div>

          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm shrink-0">
            <button 
              onClick={() => setViewMode('list')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-list"></i> Liste
            </button>
            <button 
              onClick={() => setViewMode('map')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-indigo-50 text-indigo-700' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-map-marked-alt"></i> Carte
            </button>
          </div>
        </div>

        {/* Content Section */}
        {viewMode === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredWorkers.length > 0 ? (
              filteredWorkers.map(worker => (
                <div 
                  key={worker.id} 
                  className="bg-white rounded-3xl border border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-slate-200/50 hover:-translate-y-1 transition-all group cursor-pointer"
                  onClick={() => setSelectedWorker(worker)}
                >
                  <div className="p-6">
                    <div className="flex items-start justify-between mb-4">
                      <div className="relative">
                        <img src={worker.avatar} alt={worker.name} className="w-16 h-16 rounded-2xl object-cover ring-4 ring-slate-50" />
                        <span className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${worker.status === 'online' ? 'bg-emerald-500' : 'bg-amber-500'}`}></span>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-bold text-slate-900">{worker.hourlyRate}€<span className="text-xs text-slate-400 font-medium">/h</span></div>
                        <div className="flex items-center gap-1 text-amber-500 font-bold text-sm">
                          <i className="fas fa-star"></i> {worker.rating}
                        </div>
                      </div>
                    </div>

                    <h4 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-indigo-600 transition-colors">{worker.name}</h4>
                    <p className="text-slate-400 text-sm font-medium mb-4">{CATEGORIES.find(c => c.id === worker.category)?.name} • {worker.experience} d'exp.</p>

                    <div className="flex flex-wrap gap-2 mb-6">
                      {worker.skills.slice(0, 3).map((skill, idx) => (
                        <span key={idx} className="px-2.5 py-1 bg-slate-50 text-slate-600 rounded-lg text-xs font-semibold">
                          {skill}
                        </span>
                      ))}
                    </div>

                    <div className="flex items-center justify-between pt-4 border-t border-slate-100">
                      <div className="flex items-center gap-2 text-slate-500 text-xs font-medium">
                        <i className="fas fa-location-dot"></i>
                        {worker.location.address}
                      </div>
                      <button className="text-indigo-600 font-bold text-sm hover:underline">
                        Voir profil
                      </button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-full py-20 text-center">
                <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                  <i className="fas fa-search text-3xl"></i>
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Aucun expert trouvé</h3>
                <p className="text-slate-500">Essayez de modifier vos critères de recherche ou la catégorie.</p>
              </div>
            )}
          </div>
        ) : (
          <div className="bg-slate-200 rounded-3xl h-[600px] relative overflow-hidden flex items-center justify-center border-4 border-white shadow-xl">
             {/* Mock Map Background */}
             <div className="absolute inset-0 bg-[url('https://api.mapbox.com/styles/v1/mapbox/light-v10/static/2.3522,48.8566,12/1200x600?access_token=none')] bg-cover opacity-50 grayscale"></div>

             {/* Map Markers */}
             {filteredWorkers.map(worker => (
               <div 
                key={worker.id}
                className="absolute transform -translate-x-1/2 -translate-y-1/2 group cursor-pointer"
                style={{ 
                  left: `${50 + (worker.location.lng - 2.35) * 500}%`, 
                  top: `${50 - (worker.location.lat - 48.85) * 500}%` 
                }}
                onClick={() => setSelectedWorker(worker)}
               >
                 <div className="bg-white p-1 rounded-full shadow-xl ring-2 ring-indigo-600 group-hover:scale-110 transition-transform">
                   <img src={worker.avatar} className="w-10 h-10 rounded-full object-cover" alt="" />
                 </div>
                 <div className="absolute top-full left-1/2 -translate-x-1/2 mt-2 bg-slate-900 text-white text-[10px] font-bold px-2 py-1 rounded-md opacity-0 group-hover:opacity-100 transition-opacity whitespace-nowrap">
                   {worker.name} • {worker.hourlyRate}€/h
                 </div>
               </div>
             ))}

             <div className="relative z-10 bg-white/90 backdrop-blur px-6 py-3 rounded-2xl shadow-xl border border-white/50 flex items-center gap-3">
               <div className="w-3 h-3 bg-blue-500 rounded-full animate-ping"></div>
               <span className="font-bold text-slate-900 text-sm">Votre position : Paris Centre</span>
             </div>

             <div className="absolute bottom-6 right-6 flex flex-col gap-2">
               <button className="w-12 h-12 bg-white rounded-2xl shadow-xl flex items-center justify-center text-slate-600 hover:text-indigo-600 active:scale-95 transition-all">
                 <i className="fas fa-plus"></i>
               </button>
               <button className="w-12 h-12 bg-white rounded-2xl shadow-xl flex items-center justify-center text-slate-600 hover:text-indigo-600 active:scale-95 transition-all">
                 <i className="fas fa-minus"></i>
               </button>
             </div>
          </div>
        )}
      </main>

      {/* Worker Details Modal */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center px-4">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-2xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200">
            <div className="h-40 bg-indigo-600 relative">
              <button 
                onClick={() => setSelectedWorker(null)}
                className="absolute top-6 right-6 w-10 h-10 bg-white/20 hover:bg-white/40 backdrop-blur rounded-full flex items-center justify-center text-white transition-all"
              >
                <i className="fas fa-times"></i>
              </button>
              <div className="absolute -bottom-12 left-8 p-1.5 bg-white rounded-[2rem] shadow-xl">
                <img src={selectedWorker.avatar} className="w-24 h-24 rounded-[1.75rem] object-cover" alt="" />
              </div>
            </div>

            <div className="pt-16 px-8 pb-8">
              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-8">
                <div>
                  <div className="flex items-center gap-3 mb-1">
                    <h3 className="text-2xl font-black text-slate-900">{selectedWorker.name}</h3>
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold uppercase tracking-wider">Vérifié</span>
                  </div>
                  <p className="text-slate-500 font-medium flex items-center gap-2">
                    <i className="fas fa-certificate text-indigo-500"></i>
                    {CATEGORIES.find(c => c.id === selectedWorker.category)?.name} Expert • {selectedWorker.experience} d'expérience
                  </p>
                </div>
                <div className="flex flex-col items-end">
                   <div className="text-3xl font-black text-slate-900">{selectedWorker.hourlyRate}€<span className="text-sm text-slate-400 font-bold">/h</span></div>
                   <div className="flex items-center gap-1.5 text-amber-500 font-black">
                     <i className="fas fa-star"></i> {selectedWorker.rating} <span className="text-slate-300 font-medium text-sm">({selectedWorker.reviews} avis)</span>
                   </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">À propos</h4>
                  <p className="text-slate-600 leading-relaxed mb-4">
                    Spécialiste passionné avec plus de {selectedWorker.experience} dans le domaine. Disponible pour des interventions d'urgence ou des installations planifiées.
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {selectedWorker.skills.map((skill, idx) => (
                      <span key={idx} className="px-3 py-1.5 bg-slate-100 text-slate-700 rounded-xl text-xs font-bold">
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
                <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100">
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Localisation</h4>
                  <div className="flex items-start gap-3 text-slate-600 mb-6">
                    <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center shadow-sm text-indigo-600">
                      <i className="fas fa-location-dot"></i>
                    </div>
                    <div className="text-sm">
                      <p className="font-bold text-slate-900">{selectedWorker.location.address}</p>
                      <p className="text-slate-400">À environ 1.2 km de vous</p>
                    </div>
                  </div>
                  <button className="w-full bg-white text-indigo-600 border-2 border-indigo-600 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-indigo-50 transition-all">
                    <i className="fas fa-directions"></i> Me diriger
                  </button>
                </div>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={() => window.location.href = `tel:${selectedWorker.phone}`}
                  className="flex-1 bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-800 shadow-xl shadow-slate-200 transition-all active:scale-95"
                >
                  <i className="fas fa-phone-alt"></i> Appeler
                </button>
                <button className="flex-1 bg-indigo-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-indigo-700 shadow-xl shadow-indigo-200 transition-all active:scale-95">
                  <i className="fas fa-comment-dots"></i> Message
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-12 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white">
              <i className="fas fa-tools"></i>
            </div>
            <span className="text-lg font-bold">FixItNow</span>
          </div>
          <div className="text-slate-400 text-sm">
            © 2024 FixItNow. Conçu pour les voyageurs et les résidents locaux.
          </div>
          <div className="flex gap-6">
            <a href="#" className="text-slate-400 hover:text-indigo-600 transition-colors"><i className="fab fa-twitter"></i></a>
            <a href="#" className="text-slate-400 hover:text-indigo-600 transition-colors"><i className="fab fa-instagram"></i></a>
            <a href="#" className="text-slate-400 hover:text-indigo-600 transition-colors"><i className="fab fa-facebook"></i></a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue } from './services/geminiService';

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);

  // Form state for adding a new service/worker
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: 'Paris Centre'
  });

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
