import { GoogleGenAI, Type } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const diagnoseIssue = async (userInput: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `L'utilisateur a le problème suivant : "${userInput}". 
      En tant qu'assistant de maintenance professionnel pour un étranger dans une nouvelle ville, 
      identifie la catégorie de maintenance appropriée (parmi : plumbing, electrical, hvac, appliance, locksmith, general) 
      et donne un court conseil de sécurité ou une explication simple de ce qui pourrait être cassé.`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            category: {
              type: Type.STRING,
              description: "La clé de la catégorie (ex: plumbing)",
            },
            explanation: {
              type: Type.STRING,
              description: "Explication courte et rassurante.",
            },
            urgency: {
              type: Type.STRING,
              description: "Niveau d'urgence: Bas, Moyen, Haut",
            }
          },
          required: ["category", "explanation", "urgency"]
        },
      },
    });

    return JSON.parse(response.text || '{}');
  } catch (error) {
    console.error("Gemini Error:", error);
    return null;
  }
};

export const refineLocation = async (locationInput: string) => {
  try {
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `L'utilisateur a saisi la localisation suivante : "${locationInput}". 
      Si c'est un pays comme le "Cameroun" ou une ville, propose une adresse plus précise incluant une ville majeure et un quartier populaire connu. 
      Exemple: Si "Cameroun", propose "Douala, Akwa" ou "Yaoundé, Bastos".
      Retourne uniquement un format "Ville, Quartier".`,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            refinedAddress: {
              type: Type.STRING,
              description: "L'adresse formatée (Ville, Quartier)",
            }
          },
          required: ["refinedAddress"]
        },
      },
    });
    return JSON.parse(response.text || '{}').refinedAddress;
  } catch (error) {
    console.error("Gemini Location Error:", error);
    return locationInput;
  }
};

import React, { useState, useMemo, useRef } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form state for adding a new service/worker
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (error) {
      console.error("Diagnosis failed", error);
    } finally {
      setAiLoading(false);
    }
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { 
        lat: 48.8566 + (Math.random() - 0.5) * 0.1, 
        lng: 2.3522 + (Math.random() - 0.5) * 0.1, 
        address: newWorker.address || 'Adresse non spécifiée' 
      },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
  };

  const detectLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        // En conditions réelles, on utiliserait une API de Reverse Geocoding.
        // Ici on simule une détection basée sur les coordonnées ou on demande à Gemini.
        const fakeCoordString = `Lat: ${position.coords.latitude.toFixed(2)}, Lng: ${position.coords.longitude.toFixed(2)}`;
        const refined = await refineLocation(fakeCoordString);
        setNewWorker(prev => ({ ...prev, address: refined }));
        setLocationLoading(false);
      }, () => {
        alert("Impossible d'accéder à votre position.");
        setLocationLoading(false);
      });
    } else {
      alert("La géolocalisation n'est pas supportée par votre navigateur.");
      setLocationLoading(false);
    }
  };

  const handleLocationBlur = async () => {
    if (newWorker.address.length > 3) {
      setLocationLoading(true);
      const refined = await refineLocation(newWorker.address);
      setNewWorker(prev => ({ ...prev, address: refined }));
      setLocationLoading(false);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const getUrgencyColor = (urgency: string) => {
    const u = urgency.toLowerCase();
    if (u.includes('haut') || u.includes('high')) return 'text-red-600 bg-red-50 border-red-100';
    if (u.includes('moyen') || u.includes('medium')) return 'text-amber-600 bg-amber-50 border-amber-100';
    return 'text-emerald-600 bg-emerald-50 border-emerald-100';
