              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-slate-900 uppercase tracking-widest">Localisation (Ville, Quartier)</label>
                <div className="relative">
                  <input 
                    required
                    type="text" 
                    placeholder="Ex: Douala, Akwa ou Cameroun"
                    className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all pr-32"
                    value={newWorker.address}
                    onBlur={handleLocationBlur}
                    onChange={(e) => setNewWorker({...newWorker, address: e.target.value})}
                  />
                  <button 
                    type="button"
                    onClick={detectLocation}
                    disabled={locationLoading}
                    className="absolute right-2 top-2 bottom-2 bg-white border border-slate-200 text-blue-600 px-3 rounded-xl text-[10px] font-black hover:bg-blue-50 transition-all flex items-center gap-1.5"
                  >
                    {locationLoading ? <i className="fas fa-circle-notch animate-spin"></i> : <i className="fas fa-location-crosshairs"></i>}
                    DÉTECTER
                  </button>
                </div>
                <p className="text-[10px] text-slate-400 font-medium italic">Saisissez un lieu et nous préciserons le quartier automatiquement avec l'IA.</p>
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-slate-900 uppercase tracking-widest">Téléphone</label>
                <input 
                  required
                  type="tel" 
                  placeholder="+33 6 00 00 00 00"
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                  value={newWorker.phone}
                  onChange={(e) => setNewWorker({...newWorker, phone: e.target.value})}
                />
              </div>

              <div className="space-y-2">
                <label className="text-xs font-black text-slate-900 uppercase tracking-widest">Compétences (séparées par virgule)</label>
                <input 
                  required
                  type="text" 
                  placeholder="Installation, Réparation, Urgence..."
                  className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 outline-none transition-all"
                  value={newWorker.skills}
                  onChange={(e) => setNewWorker({...newWorker, skills: e.target.value})}
                />
              </div>

              <button 
                type="submit"
                className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 shadow-xl shadow-blue-200 transition-all active:scale-95"
              >
                Publier mes services
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Worker Details Modal */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center px-4 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-2xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="h-40 bg-blue-600 relative">
              <button 
                onClick={() => setSelectedWorker(null)}
                className="absolute top-6 right-6 w-10 h-10 bg-white/20 hover:bg-white/40 backdrop-blur rounded-full flex items-center justify-center text-white transition-all"
              >
                <i className="fas fa-times"></i>
              </button>
              <div className="absolute -bottom-12 left-8 p-1.5 bg-white rounded-[2rem] shadow-xl">
                <img src={selectedWorker.avatar} className="w-24 h-24 rounded-[1.75rem] object-cover" alt="" />
              </div>
            </div>

            <div className="pt-16 px-8 pb-8">
              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-8">
                <div>
                  <div className="flex items-center gap-3 mb-1">
                    <h3 className="text-2xl font-black text-slate-900">{selectedWorker.name}</h3>
                    <span className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-bold uppercase tracking-wider">Vérifié</span>
                  </div>
                  <p className="text-slate-500 font-medium flex items-center gap-2">
                    <i className="fas fa-certificate text-blue-500"></i>
                    {CATEGORIES.find(c => c.id === selectedWorker.category)?.name} Expert • {selectedWorker.experience} d'expérience
                  </p>
                </div>
                <div className="flex flex-col items-end">
                   <div className="text-3xl font-black text-slate-900">{selectedWorker.hourlyRate}€<span className="text-sm text-slate-400 font-bold">/h</span></div>
                   <div className="flex items-center gap-1.5 text-amber-500 font-black">
                     <i className="fas fa-star"></i> {selectedWorker.rating} <span className="text-slate-300 font-medium text-sm">({selectedWorker.reviews} avis)</span>
                   </div>
                </div>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div>
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">À propos</h4>
                  <p className="text-slate-600 leading-relaxed mb-4">
                    Spécialiste passionné avec plus de {selectedWorker.experience} dans le domaine. Disponible pour des interventions d'urgence ou des installations planifiées.
                  </p>
                  <div className="flex flex-wrap gap-2">
                    {selectedWorker.skills.map((skill, idx) => (
                      <span key={idx} className="px-3 py-1.5 bg-slate-100 text-slate-700 rounded-xl text-xs font-bold">
                        {skill}
                      </span>
                    ))}
                  </div>
                </div>
                <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100">
                  <h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">Localisation</h4>
                  <div className="flex items-start gap-3 text-slate-600 mb-6">
                    <div className="w-8 h-8 bg-white rounded-lg flex items-center justify-center shadow-sm text-blue-600">
                      <i className="fas fa-location-dot"></i>
                    </div>
                    <div className="text-sm">
                      <p className="font-bold text-slate-900">{selectedWorker.location.address}</p>
                      <p className="text-slate-400">À environ 1.2 km de vous</p>
                    </div>
                  </div>
                  <button className="w-full bg-white text-blue-600 border-2 border-blue-600 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-blue-50 transition-all">
                    <i className="fas fa-directions"></i> Me diriger via Map
                  </button>
                </div>
              </div>

              <div className="flex gap-4">
                <button 
                  onClick={() => window.location.href = `tel:${selectedWorker.phone}`}
                  className="flex-1 bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-800 shadow-xl shadow-slate-200 transition-all active:scale-95"
                >
                  <i className="fas fa-phone-alt"></i> Appeler
                </button>
                <button className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 shadow-xl shadow-blue-200 transition-all active:scale-95">
                  <i className="fas fa-comment-dots"></i> Message
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer */}
      <footer className="bg-white border-t border-slate-200 py-12 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white">
              <i className="fas fa-tools"></i>
            </div>
            <span className="text-lg font-bold">FixItNow</span>
          </div>
          <div className="text-slate-400 text-sm">
            © 2024 FixItNow. Conçu pour les voyageurs et les résidents locaux.
          </div>
          <div className="flex gap-6">
            <a href="#" className="text-slate-400 hover:text-blue-600 transition-colors"><i className="fab fa-twitter"></i></a>
            <a href="#" className="text-slate-400 hover:text-blue-600 transition-colors"><i className="fab fa-instagram"></i></a>
            <a href="#" className="text-slate-400 hover:text-blue-600 transition-colors"><i className="fab fa-facebook"></i></a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Leaflet global

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form state for adding a new service/worker
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Get user location on mount
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        setUserLocation({
          lat: position.coords.latitude,
          lng: position.coords.longitude
        });
      }, () => {
        console.warn("Location permission denied, defaulting to center.");
      });
    }
  }, []);

  // Initialize and update map
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const center = userLocation || { lat: 48.8566, lng: 2.3522 };

      if (!mapRef.current) {
        mapRef.current = L.map(mapContainerRef.current).setView([center.lat, center.lng], 13);
        L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
          attribution: '&copy; OpenStreetMap contributors'
        }).addTo(mapRef.current);
      } else {
        mapRef.current.setView([center.lat, center.lng], 13);
      }

      // Clear old markers if any (simple implementation)
      mapRef.current.eachLayer((layer: any) => {
        if (layer instanceof L.Marker) {
          mapRef.current.removeLayer(layer);
        }
      });

      // Add worker markers
      filteredWorkers.forEach(worker => {
        const marker = L.marker([worker.location.lat, worker.location.lng]).addTo(mapRef.current);
        marker.bindPopup(`
          <div class="p-2">
            <b class="text-blue-600">${worker.name}</b><br/>
            ${worker.hourlyRate}€/h • ${worker.rating}★
          </div>
        `);
        marker.on('click', () => setSelectedWorker(worker));
      });

      // Add user marker
      if (userLocation) {
        const userIcon = L.divIcon({
          className: 'custom-div-icon',
          html: "<div style='background-color: #2563eb; width: 12px; height: 12px; border-radius: 50%; border: 2px solid white; box-shadow: 0 0 10px rgba(0,0,0,0.3);'></div>",
          iconSize: [12, 12],
          iconAnchor: [6, 6]
        });
        L.marker([userLocation.lat, userLocation.lng], { icon: userIcon }).addTo(mapRef.current).bindPopup("Vous êtes ici");
      }
    }
  }, [viewMode, userLocation, workers, selectedCategory]);

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (error) {
      console.error("Diagnosis failed", error);
    } finally {
      setAiLoading(false);
    }
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    const lat = userLocation?.lat || 48.8566 + (Math.random() - 0.5) * 0.1;
    const lng = userLocation?.lng || 2.3522 + (Math.random() - 0.5) * 0.1;

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { 
        lat, 
        lng, 
        address: newWorker.address || 'Adresse détectée' 
      },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
  };

  const detectLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const lat = position.coords.latitude;
        const lng = position.coords.longitude;
        setUserLocation({ lat, lng });
        const coordString = `Lat: ${lat.toFixed(4)}, Lng: ${lng.toFixed(4)}`;
        const refined = await refineLocation(coordString);
        setNewWorker(prev => ({ ...prev, address: refined }));
        setLocationLoading(false);
      }, () => {
        alert("Impossible d'accéder à votre position. Veuillez saisir votre ville.");
        setLocationLoading(false);
      });
    } else {
      alert("La géolocalisation n'est pas supportée.");
      setLocationLoading(false);
    }
  };

  const handleLocationBlur = async () => {
    if (newWorker.address.length > 3) {
      setLocationLoading(true);
      const refined = await refineLocation(newWorker.address);
      setNewWorker(prev => ({ ...prev, address: refined }));
      setLocationLoading(false);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const getUrgencyColor = (urgency: string) => {
    const u = urgency.toLowerCase();
    if (u.includes('haut') || u.includes('high')) return 'text-red-600 bg-red-50 border-red-100';
    if (u.includes('moyen') || u.includes('medium')) return 'text-amber-600 bg-amber-50 border-amber-100';
    return 'text-emerald-600 bg-emerald-50 border-emerald-100';
  };

  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900 text-slate-900">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={resetFilters}>
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <i className="fas fa-tools text-xl"></i>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">FixIt<span className="text-blue-600">Now</span></h1>
          </div>
          <nav className="hidden md:flex items-center gap-8">
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors">Accueil</a>
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors">Services</a>
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-blue-600 text-white px-5 py-2.5 rounded-full text-sm font-bold hover:bg-blue-700 transition-all shadow-md active:scale-95"
            >
              Ajouter mon service
            </button>
          </nav>
          <button className="md:hidden text-slate-500">
            <i className="fas fa-bars text-xl"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-8 md:py-12">
        {/* Hero & Search Section */}
        <section className="mb-12 text-center md:text-left">
          <div className="max-w-3xl">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 mb-6 leading-[1.15]">
              Un pépin technique ? <br/>
              <span className="text-blue-600">On s'occupe de tout.</span>
            </h2>
            <p className="text-lg text-slate-600 mb-10 max-w-xl">
              Nouveau en ville ? Ne paniquez pas. Décrivez votre problème et notre IA identifiera l'expert idéal.
            </p>

            <div className="relative group max-w-2xl">
              <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                <i className="fas fa-wand-magic-sparkles text-slate-400 group-focus-within:text-blue-500 transition-colors"></i>
              </div>
              <input 
                type="text" 
                placeholder="Ex: Mon évier est bouché et l'eau déborde..."
                className="block w-full pl-14 pr-36 py-5 bg-white border border-slate-200 rounded-2xl shadow-xl shadow-slate-200/50 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-slate-900 placeholder:text-slate-400 outline-none text-lg"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAiDiagnose()}
              />
              <button 
                onClick={handleAiDiagnose}
                disabled={aiLoading}
                className="absolute right-2.5 top-2.5 bottom-2.5 bg-blue-600 text-white px-8 rounded-xl font-bold hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 flex items-center gap-2 shadow-lg shadow-blue-200"
              >
                {aiLoading ? <i className="fas fa-circle-notch animate-spin"></i> : <i className="fas fa-bolt"></i>}
                <span>Analyser</span>
              </button>
            </div>
          </div>
        </section>

        {/* AI Result Banner */}
        {aiResult && (
          <div className="mb-12 p-8 bg-white border border-blue-100 rounded-3xl shadow-xl shadow-blue-100/20 animate-in fade-in slide-in-from-bottom-4 duration-500 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-5">
              <i className="fas fa-robot text-9xl"></i>
            </div>
            <div className="flex flex-col md:flex-row items-start gap-6 relative z-10">
              <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-200">
                <i className="fas fa-brain text-2xl"></i>
              </div>
              <div className="flex-1">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
                  <h3 className="text-xl font-bold text-slate-900">Diagnostic de l'IA FixIt</h3>
                  <div className="flex gap-2">
                    <span className={`px-4 py-1.5 rounded-full text-xs font-bold border ${getUrgencyColor(aiResult.urgency)}`}>
                      <i className="fas fa-clock mr-2"></i>Urgence: {aiResult.urgency}
                    </span>
                    <button onClick={() => setAiResult(null)} className="text-slate-400 hover:text-slate-600 transition-colors">
                      <i className="fas fa-times"></i>
                    </button>
                  </div>
                </div>
                <p className="text-slate-600 text-lg leading-relaxed mb-6">
                  {aiResult.explanation}
                </p>
                <div className="flex flex-wrap gap-3">
                  <div className="bg-blue-50 text-blue-700 px-4 py-2 rounded-xl text-sm font-semibold flex items-center gap-2 border border-blue-100">
                    <i className="fas fa-check-circle"></i>
                    Catégorie recommandée : {CATEGORIES.find(c => c.id === aiResult.category)?.name || aiResult.category}
                  </div>
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Filters & View Toggle */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-8">
          <div className="flex items-center gap-2 overflow-x-auto pb-2 w-full md:w-auto no-scrollbar">
            <button 
              onClick={() => setSelectedCategory(null)}
              className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold transition-all ${!selectedCategory ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-blue-300'}`}
            >
              Tous
            </button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id}
                onClick={() => setSelectedCategory(cat.id)}
                className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold flex items-center gap-2 transition-all ${selectedCategory === cat.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-blue-300'}`}
              >
                <i className={`fas ${cat.icon}`}></i>
                {cat.name}
              </button>
            ))}
          </div>

          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm shrink-0">
            <button 
              onClick={() => setViewMode('list')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-blue-50 text-blue-700' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-list"></i> Liste
            </button>
            <button 
              onClick={() => setViewMode('map')}
              className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-blue-50 text-blue-700' : 'text-slate-400 hover:text-slate-600'}`}
            >
              <i className="fas fa-map-marked-alt"></i> Carte
            </button>
          </div>
        </div>

        {/* Content Section */}
        {viewMode === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredWorkers.length > 0 ? (
              filteredWorkers.map(worker => (
                <div 
                  key={worker.id} 
                  className="bg-white rounded-3xl border border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-slate-200/50 hover:-translate-y-1 transition-all group cursor-pointer"
                  onClick={() => setSelectedWorker(worker)}
                >
                  <div className="p-6">
                    <div className="flex items-start justify-between mb-4">
                      <div className="relative">
                        <img src={worker.avatar} alt={worker.name} className="w-16 h-16 rounded-2xl object-cover ring-4 ring-slate-50" />
                        <span className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${worker.status === 'online' ? 'bg-emerald-500' : 'bg-amber-500'}`}></span>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-bold text-slate-900">{worker.hourlyRate}€<span className="text-xs text-slate-400 font-medium">/h</span></div>
                        <div className="flex items-center gap-1 text-amber-500 font-bold text-sm">
                          <i className="fas fa-star"></i> {worker.rating}
                        </div>
                      </div>
                    </div>
                    <h4 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-blue-600 transition-colors">{worker.name}</h4>
                    <p className="text-slate-400 text-sm font-medium mb-4">{CATEGORIES.find(c => c.id === worker.category)?.name} • {worker.experience} d'exp.</p>
                    <div className="flex flex-wrap gap-2 mb-6">
                      {worker.skills.slice(0, 3).map((skill, idx) => (
                        <span key={idx} className="px-2.5 py-1 bg-slate-50 text-slate-600 rounded-lg text-xs font-semibold">{skill}</span>
                      ))}
                    </div>
                    <div className="flex items-center justify-between pt-4 border-t border-slate-100">
                      <div className="flex items-center gap-2 text-slate-500 text-xs font-medium">
                        <i className="fas fa-location-dot"></i>
                        {worker.location.address}
                      </div>
                      <button className="text-blue-600 font-bold text-sm hover:underline">Voir profil</button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-full py-20 text-center">
                <div className="w-20 h-20 bg-slate-100 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
                  <i className="fas fa-search text-3xl"></i>
                </div>
                <h3 className="text-xl font-bold text-slate-900 mb-2">Aucun expert trouvé</h3>
                <p className="text-slate-500">Essayez de modifier vos critères.</p>
              </div>
            )}
          </div>
        ) : (
          <div className="bg-white rounded-3xl h-[600px] relative overflow-hidden border-4 border-white shadow-xl">
             <div ref={mapContainerRef} className="w-full h-full"></div>
             <div className="absolute top-4 right-4 z-[10] flex flex-col gap-2">
                <button 
                  onClick={() => userLocation && mapRef.current?.setView([userLocation.lat, userLocation.lng], 15)}
                  className="w-12 h-12 bg-white rounded-2xl shadow-xl flex items-center justify-center text-blue-600 hover:bg-blue-50 active:scale-95 transition-all border border-slate-100"
                >
                  <i className="fas fa-crosshairs"></i>
                </button>
             </div>
             <div className="absolute bottom-6 left-1/2 -translate-x-1/2 z-[10] bg-white/90 backdrop-blur px-6 py-3 rounded-2xl shadow-xl border border-white/50 flex items-center gap-3">
               <div className="w-3 h-3 bg-blue-500 rounded-full animate-ping"></div>
               <span className="font-bold text-slate-900 text-sm">Exploration en cours...</span>
             </div>
          </div>
        )}
      </main>

      {/* Pro Modal */}
      {isProModalOpen && (
        <div className="fixed inset-0 z-[110] flex items-center justify-center px-4 overflow-y-auto py-10">
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setIsProModalOpen(false)}></div>
          <div className="bg-white w-full max-w-xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-blue-50/50">
              <div>
                <h3 className="text-2xl font-black text-slate-900">Devenir Partenaire</h3>
                <p className="text-slate-500 text-sm">Inscrivez-vous et soyez visible sur la carte.</p>
              </div>
              <button onClick={() => setIsProModalOpen(false)} className="w-10 h-10 bg-white border border-slate-200 rounded-full flex items-center justify-center text-slate-400 hover:text-slate-600 transition-all shadow-sm">
                <i className="fas fa-times"></i>
              </button>
            </div>

            <form onSubmit={handleAddWorker} className="p-8 space-y-6">
              <div className="flex flex-col items-center gap-4 mb-2">
                <div onClick={() => fileInputRef.current?.click()} className="w-24 h-24 rounded-3xl bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer overflow-hidden group hover:border-blue-400 transition-all">
                  {newWorker.avatar ? <img src={newWorker.avatar} className="w-full h-full object-cover" alt="Profile" /> : <div className="text-center text-slate-400 group-hover:text-blue-500"><i className="fas fa-camera text-xl mb-1"></i><p className="text-[10px] font-bold">PHOTO</p></div>}
                </div>
                <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Nom Complet" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.name} onChange={(e) => setNewWorker({...newWorker, name: e.target.value})} />
                <select className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.category} onChange={(e) => setNewWorker({...newWorker, category: e.target.value})}>
                  {CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Expérience" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.experience} onChange={(e) => setNewWorker({...newWorker, experience: e.target.value})} />
                <input required type="number" placeholder="Tarif (€)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.hourlyRate} onChange={(e) => setNewWorker({...newWorker, hourlyRate: e.target.value})} />
              </div>

              <div className="space-y-2">
                <div className="relative">
                  <input required type="text" placeholder="Saisir Lieu (ex: Cameroun, Douala)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none pr-32" value={newWorker.address} onBlur={handleLocationBlur} onChange={(e) => setNewWorker({...newWorker, address: e.target.value})} />
                  <button type="button" onClick={detectLocation} disabled={locationLoading} className="absolute right-2 top-2 bottom-2 bg-white border border-slate-200 text-blue-600 px-3 rounded-xl text-[10px] font-black hover:bg-blue-50">
                    {locationLoading ? <i className="fas fa-circle-notch animate-spin"></i> : "DÉTECTER MA POSITION"}
                  </button>
                </div>
                <p className="text-[10px] text-slate-400 italic">L'IA précisera le quartier si vous entrez juste une ville ou un pays.</p>
              </div>

              <input required type="tel" placeholder="Téléphone" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.phone} onChange={(e) => setNewWorker({...newWorker, phone: e.target.value})} />
              <input required type="text" placeholder="Compétences (virgules)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.skills} onChange={(e) => setNewWorker({...newWorker, skills: e.target.value})} />

              <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 shadow-xl shadow-blue-200 transition-all active:scale-95">Publier mes services</button>
            </form>
          </div>
        </div>
      )}

      {/* Worker Details Modal */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[120] flex items-center justify-center px-4 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-2xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="h-40 bg-blue-600 relative">
              <button onClick={() => setSelectedWorker(null)} className="absolute top-6 right-6 w-10 h-10 bg-white/20 hover:bg-white/40 backdrop-blur rounded-full flex items-center justify-center text-white transition-all"><i className="fas fa-times"></i></button>
              <div className="absolute -bottom-12 left-8 p-1.5 bg-white rounded-[2rem] shadow-xl"><img src={selectedWorker.avatar} className="w-24 h-24 rounded-[1.75rem] object-cover" alt="" /></div>
            </div>
            <div className="pt-16 px-8 pb-8">
              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-8">
                <div><h3 className="text-2xl font-black text-slate-900">{selectedWorker.name}</h3><p className="text-slate-500 font-medium">{selectedWorker.experience} d'expérience</p></div>
                <div className="flex flex-col items-end"><div className="text-3xl font-black text-slate-900">{selectedWorker.hourlyRate}€/h</div><div className="text-amber-500 font-black"><i className="fas fa-star"></i> {selectedWorker.rating}</div></div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div><h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">À propos</h4><p className="text-slate-600 text-sm leading-relaxed mb-4">Disponible pour interventions immédiates à {selectedWorker.location.address}.</p></div>
                <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100"><h4 className="text-sm font-black text-slate-900 uppercase mb-4">Localisation</h4><p className="font-bold text-slate-900 mb-6">{selectedWorker.location.address}</p>
                <button 
                  onClick={() => {
                    window.open(`https://www.google.com/maps/dir/?api=1&destination=${selectedWorker.location.lat},${selectedWorker.location.lng}`, '_blank');
                  }}
                  className="w-full bg-white text-blue-600 border-2 border-blue-600 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-blue-50"
                >
                  <i className="fas fa-directions"></i> Me diriger via Google Maps
                </button>
                </div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => window.location.href = `tel:${selectedWorker.phone}`} className="flex-1 bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-800 shadow-xl transition-all"><i className="fas fa-phone-alt"></i> Appeler</button>
                <button className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 shadow-xl transition-all"><i className="fas fa-comment-dots"></i> Message</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 py-12 mt-12">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 flex flex-col md:flex-row justify-between items-center gap-8">
          <div className="flex items-center gap-2"><div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white"><i className="fas fa-tools"></i></div><span className="text-lg font-bold">FixItNow</span></div>
          <div className="text-slate-400 text-sm">© 2024 FixItNow. Géolocalisation intelligente intégrée.</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Leaflet global from index.html

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Form state for adding a new service/worker
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Get user real location on mount
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        const coords = {
          lat: position.coords.latitude,
          lng: position.coords.longitude
        };
        setUserLocation(coords);
        console.log("Real location detected:", coords);
      }, (error) => {
        console.warn("Location permission denied or failed:", error.message);
      }, { enableHighAccuracy: true });
    }
  }, []);

  // Filter workers based on search and category
  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  // Handle map display and markers
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      // Small delay to ensure container is fully rendered and has height
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;

        const center = userLocation || { lat: 48.8566, lng: 2.3522 };

        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current).setView([center.lat, center.lng], 13);
          L.tileLayer('https://{s}.tile.openstreetmap.fr/hot/{z}/{x}/{y}.png', {
            maxZoom: 19,
            attribution: '&copy; OpenStreetMap contributors, Tiles style by Humanitarian OpenStreetMap Team'
          }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
        } else {
          mapRef.current.invalidateSize();
          mapRef.current.setView([center.lat, center.lng], 13);
        }

        // Clear existing markers
        markersLayerRef.current.clearLayers();

        // Add worker markers with custom DivIcons (Avoids broken default image bug)
        filteredWorkers.forEach(worker => {
          const workerIcon = L.divIcon({
            className: 'worker-marker-container',
            html: `<div class="worker-marker-container">
                    <img src="${worker.avatar}" class="worker-marker-icon" style="width: 36px; height: 36px; object-fit: cover;">
                   </div>`,
            iconSize: [36, 36],
            iconAnchor: [18, 18]
          });

          const marker = L.marker([worker.location.lat, worker.location.lng], { icon: workerIcon }).addTo(markersLayerRef.current);
          marker.bindPopup(`
            <div class="p-2 text-center min-w-[120px]">
              <div class="font-bold text-blue-600 mb-1">${worker.name}</div>
              <div class="text-xs text-slate-500 mb-2">${CATEGORIES.find(c => c.id === worker.category)?.name}</div>
              <div class="text-sm font-black">${worker.hourlyRate}€/h</div>
              <button onclick="window.dispatchEvent(new CustomEvent('open-worker', {detail: '${worker.id}'}))" class="mt-2 w-full bg-blue-600 text-white text-[10px] py-1 rounded-lg">VOIR PROFIL</button>
            </div>
          `);
        });

        // Add user marker
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker',
            html: `<div style="background-color: #2563eb; width: 16px; height: 16px; border-radius: 50%; border: 3px solid white; box-shadow: 0 0 15px rgba(37,99,235,0.5);"></div>`,
            iconSize: [16, 16],
            iconAnchor: [8, 8]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 1000 }).addTo(markersLayerRef.current).bindPopup("Vous êtes ici");
        }
      }, 100);

      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, workers, selectedCategory]);

  // Listen for worker popup button clicks
  useEffect(() => {
    const handleOpenWorker = (e: any) => {
      const worker = workers.find(w => w.id === e.detail);
      if (worker) setSelectedWorker(worker);
    };
    window.addEventListener('open-worker', handleOpenWorker);
    return () => window.removeEventListener('open-worker', handleOpenWorker);
  }, [workers]);

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    setAiResult(null);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (error) {
      console.error("Diagnosis failed", error);
    } finally {
      setAiLoading(false);
    }
  };

  const handleAddWorker = (e: React.FormEvent) => {
    e.preventDefault();
    // Default to user's real detected location if possible, otherwise randomize slightly near the center
    const lat = userLocation?.lat || (48.8566 + (Math.random() - 0.5) * 0.1);
    const lng = userLocation?.lng || (2.3522 + (Math.random() - 0.5) * 0.1);

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat, lng, address: newWorker.address || 'Ma position actuelle' },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
  };

  const detectLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const coords = { lat: position.coords.latitude, lng: position.coords.longitude };
        setUserLocation(coords);

        // Reverse Geocoding simulation with Gemini refinement
        const coordString = `Lat: ${coords.lat.toFixed(4)}, Lng: ${coords.lng.toFixed(4)}`;
        const refined = await refineLocation(coordString);
        setNewWorker(prev => ({ ...prev, address: refined }));
        setLocationLoading(false);

        // Center map if it's open
        if (mapRef.current) mapRef.current.flyTo([coords.lat, coords.lng], 15);
      }, (err) => {
        alert("Erreur de géolocalisation: " + err.message);
        setLocationLoading(false);
      }, { enableHighAccuracy: true });
    } else {
      alert("La géolocalisation n'est pas supportée.");
      setLocationLoading(false);
    }
  };

  const handleLocationBlur = async () => {
    if (newWorker.address.length > 3) {
      setLocationLoading(true);
      const refined = await refineLocation(newWorker.address);
      setNewWorker(prev => ({ ...prev, address: refined }));
      setLocationLoading(false);
    }
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900 text-slate-900">
      {/* Header */}
      <header className="bg-white/80 backdrop-blur-md border-b border-slate-200 sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-16 flex items-center justify-between">
          <div className="flex items-center gap-2 cursor-pointer" onClick={resetFilters}>
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-blue-200">
              <i className="fas fa-tools text-xl"></i>
            </div>
            <h1 className="text-xl font-bold tracking-tight text-slate-900">FixIt<span className="text-blue-600">Now</span></h1>
          </div>
          <nav className="hidden md:flex items-center gap-8">
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors">Accueil</a>
            <a href="#" className="text-sm font-semibold text-slate-600 hover:text-blue-600 transition-colors">Services</a>
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-blue-600 text-white px-5 py-2.5 rounded-full text-sm font-bold hover:bg-blue-700 transition-all shadow-md active:scale-95"
            >
              Ajouter mon service
            </button>
          </nav>
          <button className="md:hidden text-slate-500">
            <i className="fas fa-bars text-xl"></i>
          </button>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-8 md:py-12">
        {/* Hero & Search Section */}
        <section className="mb-12 text-center md:text-left">
          <div className="max-w-3xl">
            <h2 className="text-4xl md:text-5xl font-extrabold text-slate-900 mb-6 leading-[1.15]">
              Un pépin technique ? <br/>
              <span className="text-blue-600">On s'occupe de tout.</span>
            </h2>
            <p className="text-lg text-slate-600 mb-10 max-w-xl">
              Nouveau en ville ? Ne paniquez pas. Décrivez votre problème et notre IA identifiera l'expert idéal.
            </p>

            <div className="relative group max-w-2xl">
              <div className="absolute inset-y-0 left-0 pl-5 flex items-center pointer-events-none">
                <i className="fas fa-wand-magic-sparkles text-slate-400 group-focus-within:text-blue-500 transition-colors"></i>
              </div>
              <input 
                type="text" 
                placeholder="Ex: Mon évier est bouché et l'eau déborde..."
                className="block w-full pl-14 pr-36 py-5 bg-white border border-slate-200 rounded-2xl shadow-xl shadow-slate-200/50 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-500 transition-all text-slate-900 placeholder:text-slate-400 outline-none text-lg"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAiDiagnose()}
              />
              <button 
                onClick={handleAiDiagnose}
                disabled={aiLoading}
                className="absolute right-2.5 top-2.5 bottom-2.5 bg-blue-600 text-white px-8 rounded-xl font-bold hover:bg-blue-700 active:scale-95 transition-all disabled:opacity-50 flex items-center gap-2 shadow-lg shadow-blue-200"
              >
                {aiLoading ? <i className="fas fa-circle-notch animate-spin"></i> : <i className="fas fa-bolt"></i>}
                <span>Analyser</span>
              </button>
            </div>
          </div>
        </section>

        {/* AI Result Banner */}
        {aiResult && (
          <div className="mb-12 p-8 bg-white border border-blue-100 rounded-3xl shadow-xl shadow-blue-100/20 animate-in fade-in slide-in-from-bottom-4 duration-500 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-4 opacity-5"><i className="fas fa-robot text-9xl"></i></div>
            <div className="flex flex-col md:flex-row items-start gap-6 relative z-10">
              <div className="w-14 h-14 bg-blue-600 rounded-2xl flex items-center justify-center text-white shrink-0 shadow-lg shadow-blue-200"><i className="fas fa-brain text-2xl"></i></div>
              <div className="flex-1">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
                  <h3 className="text-xl font-bold text-slate-900">Diagnostic de l'IA FixIt</h3>
                  <div className="flex gap-2">
                    <span className="px-4 py-1.5 rounded-full text-xs font-bold border text-blue-600 bg-blue-50 border-blue-100">
                      <i className="fas fa-clock mr-2"></i>Urgence: {aiResult.urgency}
                    </span>
                    <button onClick={() => setAiResult(null)} className="text-slate-400 hover:text-slate-600"><i className="fas fa-times"></i></button>
                  </div>
                </div>
                <p className="text-slate-600 text-lg leading-relaxed mb-6">{aiResult.explanation}</p>
                <div className="bg-blue-50 text-blue-700 px-4 py-2 rounded-xl text-sm font-semibold flex items-center gap-2 border border-blue-100 w-fit">
                  <i className="fas fa-check-circle"></i> Catégorie : {CATEGORIES.find(c => c.id === aiResult.category)?.name || aiResult.category}
                </div>
              </div>
            </div>
          </div>
        )}

        {/* Filters & View Toggle */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-8">
          <div className="flex items-center gap-2 overflow-x-auto pb-2 w-full md:w-auto no-scrollbar">
            <button 
              onClick={() => setSelectedCategory(null)}
              className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold transition-all ${!selectedCategory ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-blue-300'}`}
            >Tous</button>
            {CATEGORIES.map(cat => (
              <button 
                key={cat.id}
                onClick={() => setSelectedCategory(cat.id)}
                className={`whitespace-nowrap px-5 py-2.5 rounded-full text-sm font-bold flex items-center gap-2 transition-all ${selectedCategory === cat.id ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' : 'bg-white text-slate-600 border border-slate-200 hover:border-blue-300'}`}
              ><i className={`fas ${cat.icon}`}></i>{cat.name}</button>
            ))}
          </div>
          <div className="flex bg-white p-1 rounded-xl border border-slate-200 shadow-sm shrink-0">
            <button onClick={() => setViewMode('list')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'list' ? 'bg-blue-50 text-blue-700' : 'text-slate-400 hover:text-slate-600'}`}><i className="fas fa-list"></i> Liste</button>
            <button onClick={() => setViewMode('map')} className={`px-4 py-2 rounded-lg text-sm font-bold transition-all flex items-center gap-2 ${viewMode === 'map' ? 'bg-blue-50 text-blue-700' : 'text-slate-400 hover:text-slate-600'}`}><i className="fas fa-map-marked-alt"></i> Carte</button>
          </div>
        </div>

        {/* Content Section */}
        {viewMode === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
            {filteredWorkers.length > 0 ? (
              filteredWorkers.map(worker => (
                <div key={worker.id} className="bg-white rounded-3xl border border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-slate-200/50 hover:-translate-y-1 transition-all group cursor-pointer" onClick={() => setSelectedWorker(worker)}>
                  <div className="p-6">
                    <div className="flex items-start justify-between mb-4">
                      <div className="relative">
                        <img src={worker.avatar} alt={worker.name} className="w-16 h-16 rounded-2xl object-cover ring-4 ring-slate-50" />
                        <span className={`absolute -bottom-1 -right-1 w-4 h-4 rounded-full border-2 border-white ${worker.status === 'online' ? 'bg-emerald-500' : 'bg-amber-500'}`}></span>
                      </div>
                      <div className="text-right">
                        <div className="text-xl font-bold text-slate-900">{worker.hourlyRate}€/h</div>
                        <div className="flex items-center gap-1 text-amber-500 font-bold text-sm"><i className="fas fa-star"></i> {worker.rating}</div>
                      </div>
                    </div>
                    <h4 className="text-lg font-bold text-slate-900 mb-1 group-hover:text-blue-600 transition-colors">{worker.name}</h4>
                    <p className="text-slate-400 text-sm font-medium mb-4">{CATEGORIES.find(c => c.id === worker.category)?.name} • {worker.experience} exp.</p>
                    <div className="flex flex-wrap gap-2 mb-6">
                      {worker.skills.slice(0, 3).map((skill, idx) => (
                        <span key={idx} className="px-2.5 py-1 bg-slate-50 text-slate-600 rounded-lg text-xs font-semibold">{skill}</span>
                      ))}
                    </div>
                    <div className="flex items-center justify-between pt-4 border-t border-slate-100">
                      <div className="flex items-center gap-2 text-slate-500 text-xs font-medium"><i className="fas fa-location-dot"></i>{worker.location.address}</div>
                      <button className="text-blue-600 font-bold text-sm">Voir profil</button>
                    </div>
                  </div>
                </div>
              ))
            ) : (
              <div className="col-span-full py-20 text-center"><h3 className="text-xl font-bold text-slate-900 mb-2">Aucun expert trouvé</h3></div>
            )}
          </div>
        ) : (
          <div className="bg-white rounded-[2rem] h-[600px] relative overflow-hidden border-4 border-white shadow-2xl">
             <div ref={mapContainerRef} className="w-full h-full"></div>
             <div className="absolute top-4 right-4 z-[1000] flex flex-col gap-2">
                <button 
                  onClick={() => userLocation && mapRef.current?.flyTo([userLocation.lat, userLocation.lng], 15)}
                  className="w-12 h-12 bg-white rounded-2xl shadow-xl flex items-center justify-center text-blue-600 hover:bg-blue-50 active:scale-95 transition-all border border-slate-200"
                ><i className="fas fa-crosshairs"></i></button>
             </div>
          </div>
        )}
      </main>

      {/* Pro Modal */}
      {isProModalOpen && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center px-4 overflow-y-auto py-10">
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setIsProModalOpen(false)}></div>
          <div className="bg-white w-full max-w-xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="p-8 border-b border-slate-100 flex items-center justify-between bg-blue-50/50">
              <div><h3 className="text-2xl font-black text-slate-900">Devenir Partenaire</h3><p className="text-slate-500 text-sm">Inscrivez-vous et soyez visible sur la carte.</p></div>
              <button onClick={() => setIsProModalOpen(false)} className="w-10 h-10 bg-white border border-slate-200 rounded-full flex items-center justify-center text-slate-400 hover:text-slate-600 transition-all"><i className="fas fa-times"></i></button>
            </div>
            <form onSubmit={handleAddWorker} className="p-8 space-y-6 max-h-[70vh] overflow-y-auto">
              <div className="flex flex-col items-center gap-4 mb-2">
                <div onClick={() => fileInputRef.current?.click()} className="w-24 h-24 rounded-3xl bg-slate-100 border-2 border-dashed border-slate-300 flex items-center justify-center cursor-pointer overflow-hidden group hover:border-blue-400 transition-all">
                  {newWorker.avatar ? <img src={newWorker.avatar} className="w-full h-full object-cover" alt="Profile" /> : <div className="text-center text-slate-400 group-hover:text-blue-500"><i className="fas fa-camera text-xl mb-1"></i><p className="text-[10px] font-bold">PHOTO</p></div>}
                </div>
                <input type="file" ref={fileInputRef} onChange={handleImageChange} accept="image/*" className="hidden" />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Nom Complet" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.name} onChange={(e) => setNewWorker({...newWorker, name: e.target.value})} />
                <select className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.category} onChange={(e) => setNewWorker({...newWorker, category: e.target.value})}>
                  {CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Expérience" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.experience} onChange={(e) => setNewWorker({...newWorker, experience: e.target.value})} />
                <input required type="number" placeholder="Tarif (€)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.hourlyRate} onChange={(e) => setNewWorker({...newWorker, hourlyRate: e.target.value})} />
              </div>
              <div className="space-y-2">
                <div className="relative">
                  <input required type="text" placeholder="Saisir Lieu (ex: Douala, Akwa)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none pr-32" value={newWorker.address} onBlur={handleLocationBlur} onChange={(e) => setNewWorker({...newWorker, address: e.target.value})} />
                  <button type="button" onClick={detectLocation} disabled={locationLoading} className="absolute right-2 top-2 bottom-2 bg-white border border-slate-200 text-blue-600 px-3 rounded-xl text-[10px] font-black hover:bg-blue-50">
                    {locationLoading ? <i className="fas fa-circle-notch animate-spin"></i> : "DÉTECTER MA POSITION RÉELLE"}
                  </button>
                </div>
                <p className="text-[10px] text-slate-400 italic">L'IA précisera le quartier si vous entrez juste une ville ou un pays.</p>
              </div>
              <input required type="tel" placeholder="Téléphone" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.phone} onChange={(e) => setNewWorker({...newWorker, phone: e.target.value})} />
              <input required type="text" placeholder="Compétences (virgules)" className="w-full px-5 py-3.5 bg-slate-50 border border-slate-200 rounded-2xl outline-none" value={newWorker.skills} onChange={(e) => setNewWorker({...newWorker, skills: e.target.value})} />
              <button type="submit" className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold hover:bg-blue-700 shadow-xl transition-all active:scale-95">Publier mes services</button>
            </form>
          </div>
        </div>
      )}

      {/* Worker Details */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center px-4 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-2xl rounded-[32px] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="h-40 bg-blue-600 relative">
              <button onClick={() => setSelectedWorker(null)} className="absolute top-6 right-6 w-10 h-10 bg-white/20 hover:bg-white/40 backdrop-blur rounded-full flex items-center justify-center text-white"><i className="fas fa-times"></i></button>
              <div className="absolute -bottom-12 left-8 p-1.5 bg-white rounded-[2rem] shadow-xl"><img src={selectedWorker.avatar} className="w-24 h-24 rounded-[1.75rem] object-cover" alt="" /></div>
            </div>
            <div className="pt-16 px-8 pb-8">
              <div className="flex flex-col md:flex-row md:items-start justify-between gap-4 mb-8">
                <div><h3 className="text-2xl font-black text-slate-900">{selectedWorker.name}</h3><p className="text-slate-500 font-medium">{selectedWorker.experience} d'expérience</p></div>
                <div className="flex flex-col items-end"><div className="text-3xl font-black text-slate-900">{selectedWorker.hourlyRate}€/h</div><div className="text-amber-500 font-black"><i className="fas fa-star"></i> {selectedWorker.rating}</div></div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
                <div><h4 className="text-sm font-black text-slate-900 uppercase tracking-widest mb-4">À propos</h4><p className="text-slate-600 text-sm leading-relaxed mb-4">Disponible pour interventions à {selectedWorker.location.address}.</p></div>
                <div className="bg-slate-50 rounded-2xl p-6 border border-slate-100"><h4 className="text-sm font-black text-slate-900 uppercase mb-4">Localisation</h4><p className="font-bold text-slate-900 mb-6">{selectedWorker.location.address}</p>
                <button 
                  onClick={() => window.open(`https://www.google.com/maps/dir/?api=1&destination=${selectedWorker.location.lat},${selectedWorker.location.lng}`, '_blank')}
                  className="w-full bg-white text-blue-600 border-2 border-blue-600 py-3 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-blue-50"
                ><i className="fas fa-directions"></i> Itinéraire Google Maps</button>
                </div>
              </div>
              <div className="flex gap-4">
                <button onClick={() => window.location.href = `tel:${selectedWorker.phone}`} className="flex-1 bg-slate-900 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-slate-800 shadow-xl transition-all"><i className="fas fa-phone-alt"></i> Appeler</button>
                <button className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-3 hover:bg-blue-700 shadow-xl transition-all"><i className="fas fa-comment-dots"></i> Message</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 py-8 mt-12 text-center text-slate-400 text-xs">
        © 2024 FixItNow. Expertise et Proximité.
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Global Leaflet

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Formulaire pour ajouter un service
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Détection de la position réelle au démarrage
  useEffect(() => {
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        const coords = {
          lat: position.coords.latitude,
          lng: position.coords.longitude
        };
        setUserLocation(coords);
        console.log("Position réelle détectée:", coords);
      }, (error) => {
        console.warn("Accès position refusé. Mode démo Paris par défaut.", error.message);
      }, { enableHighAccuracy: true });
    }
  }, []);

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  // Initialisation et mise à jour de la carte
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;

        const center = userLocation || { lat: 48.8566, lng: 2.3522 };

        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);

          // Style de carte type Google Maps / Moderne
          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);

          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
        } else {
          mapRef.current.invalidateSize();
          mapRef.current.setView([center.lat, center.lng], mapRef.current.getZoom());
        }

        markersLayerRef.current.clearLayers();

        // Marqueurs des travailleurs
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar">`,
            iconSize: [40, 40],
            iconAnchor: [20, 20]
          });

          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => setSelectedWorker(worker));
        });

        // Marqueur utilisateur
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-container',
            html: `<div class="user-location-dot"></div>`,
            iconSize: [18, 18],
            iconAnchor: [9, 9]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 }).addTo(markersLayerRef.current);
        }
      }, 200);

      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, filteredWorkers]);

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleAddService = (e: React.FormEvent) => {
    e.preventDefault();
    const lat = userLocation?.lat || (48.8566 + (Math.random() - 0.5) * 0.05);
    const lng = userLocation?.lng || (2.3522 + (Math.random() - 0.5) * 0.05);

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat, lng, address: newWorker.address || 'Ma position réelle' },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
    alert("Votre service a été ajouté avec succès et est maintenant visible sur la carte !");
  };

  const handleDetectLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(async (position) => {
        const lat = position.coords.latitude;
        const lng = position.coords.longitude;
        setUserLocation({ lat, lng });

        // Utilisation de Gemini pour transformer les coordonnées en adresse Ville/Quartier
        const refined = await refineLocation(`Lat: ${lat}, Lng: ${lng}`);
        setNewWorker(prev => ({ ...prev, address: refined }));
        setLocationLoading(false);
        if (mapRef.current) mapRef.current.flyTo([lat, lng], 15);
      }, (err) => {
        alert("Géolocalisation impossible. Saisissez votre ville manuellement.");
        setLocationLoading(false);
      });
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Navbar Premium */}
      <header className="bg-white/90 backdrop-blur-lg border-b border-slate-200 sticky top-0 z-[1001]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={resetFilters}>
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-200">
              <i className="fas fa-tools text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">FixIt<span className="text-blue-600">Now</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Experts de proximité</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-2xl font-extrabold shadow-lg shadow-orange-100 transition-all active:scale-95 flex items-center gap-2"
            >
              <i className="fas fa-briefcase"></i>
              Gagner de l'argent
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-all">
              <i className="fas fa-user"></i>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-10">
        {/* Recherche intelligente */}
        <section className="mb-12 relative">
          <div className="max-w-2xl">
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-6 leading-tight">
