                <button 
                  onClick={() => window.location.href = `tel:${selectedWorker.phone}`}
                  className="flex-1 bg-slate-900 text-white py-6 rounded-3xl font-black text-lg flex items-center justify-center gap-4 hover:bg-slate-800 shadow-2xl transition-all active:scale-95 uppercase tracking-widest"
                >
                  <i className="fas fa-phone-alt"></i> Appeler
                </button>
                <button className="flex-1 bg-orange-500 text-white py-6 rounded-3xl font-black text-lg flex items-center justify-center gap-4 hover:bg-orange-600 shadow-2xl shadow-orange-100 transition-all active:scale-95 uppercase tracking-widest">
                  <i className="fas fa-comment-dots"></i> Message
                </button>
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 py-16 mt-20">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 flex flex-col items-center text-center">
          <div className="flex items-center gap-2 mb-8">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white"><i className="fas fa-tools"></i></div>
            <span className="text-xl font-black tracking-tighter">FixItNow</span>
          </div>
          <p className="text-slate-400 text-sm font-bold uppercase tracking-[0.3em] mb-4">Trouvez un expert. Partout. Maintenant.</p>
          <div className="text-slate-300 text-[10px] font-bold">© 2024 FIXITNOW GLOBAL SERVICES • TOUS DROITS RÉSERVÉS</div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Global Leaflet

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);
  const [locationDenied, setLocationDenied] = useState(false);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const routeLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Formulaire pour ajouter un service
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Détection de la position réelle au démarrage
  useEffect(() => {
    requestUserLocation();
  }, []);

  const requestUserLocation = () => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition((position) => {
        const coords = {
          lat: position.coords.latitude,
          lng: position.coords.longitude
        };
        setUserLocation(coords);
        setLocationDenied(false);
        setLocationLoading(false);
        if (mapRef.current) mapRef.current.flyTo([coords.lat, coords.lng], 14);
      }, (error) => {
        console.warn("Accès position refusé ou indisponible:", error.message);
        if (error.code === error.PERMISSION_DENIED) {
          setLocationDenied(true);
        }
        setLocationLoading(false);
      }, { enableHighAccuracy: true, timeout: 10000 });
    } else {
      setLocationLoading(false);
    }
  };

  // resetFilters clears all filters and AI diagnostic results
  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  // Initialisation et mise à jour de la carte
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;

        const center = userLocation || { lat: 48.8566, lng: 2.3522 };

        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);

          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);

          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
          routeLayerRef.current = L.layerGroup().addTo(mapRef.current);
        } else {
          mapRef.current.invalidateSize();
          if (userLocation) mapRef.current.setView([userLocation.lat, userLocation.lng], mapRef.current.getZoom());
        }

        markersLayerRef.current.clearLayers();

        // Marqueurs des travailleurs
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar">`,
            iconSize: [42, 42],
            iconAnchor: [21, 21]
          });

          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => {
            setSelectedWorker(worker);
            drawRouteTo(worker);
          });
        });

        // Marqueur utilisateur DISTINCT
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-container',
            html: `<div class="user-location-outer"><div class="user-location-inner"></div></div>`,
            iconSize: [24, 24],
            iconAnchor: [12, 12]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 })
           .addTo(markersLayerRef.current)
           .bindPopup("<div class='font-bold text-blue-600'>Vous êtes ici</div>");
        }
      }, 200);

      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, filteredWorkers]);

  const drawRouteTo = (worker: MaintenanceWorker) => {
    if (!userLocation || !routeLayerRef.current) return;
    routeLayerRef.current.clearLayers();

    // Simuler un itinéraire avec une polyline simple (plus tard on pourrait utiliser un service de routing)
    const points = [
      [userLocation.lat, userLocation.lng],
      [worker.location.lat, worker.location.lng]
    ];

    L.polyline(points, {
      color: '#2563eb',
      weight: 4,
      opacity: 0.6,
      className: 'leaflet-interactive-path'
    }).addTo(routeLayerRef.current);
  };

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleAddService = (e: React.FormEvent) => {
    e.preventDefault();
    const lat = userLocation?.lat || (48.8566 + (Math.random() - 0.5) * 0.05);
    const lng = userLocation?.lng || (2.3522 + (Math.random() - 0.5) * 0.05);

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat, lng, address: newWorker.address || 'Ma position réelle' },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
    alert("Votre service a été ajouté avec succès !");
  };

  const handleManualAddressRefine = async () => {
    if (newWorker.address.length < 3) return;
    setLocationLoading(true);
    const refined = await refineLocation(newWorker.address);
    setNewWorker(prev => ({ ...prev, address: refined }));
    setLocationLoading(false);
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans">
      {/* Alerte si localisation refusée */}
      {locationDenied && (
        <div className="bg-orange-500 text-white px-4 py-3 text-center text-sm font-bold animate-in slide-in-from-top duration-300 z-[2001] sticky top-0">
          <i className="fas fa-exclamation-triangle mr-2"></i>
          Localisation refusée. Pour de meilleurs résultats, saisissez votre ville manuellement ci-dessous.
          <button onClick={() => setLocationDenied(false)} className="ml-4 underline opacity-80 hover:opacity-100">Ignorer</button>
        </div>
      )}

      {/* Navbar Premium */}
      <header className="bg-white/90 backdrop-blur-lg border-b border-slate-200 sticky top-0 z-[1001]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer" onClick={resetFilters}>
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-200">
              <i className="fas fa-tools text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">FixIt<span className="text-blue-600">Now</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Géo-Expertise</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-2xl font-extrabold shadow-lg shadow-orange-100 transition-all active:scale-95 flex items-center gap-2"
            >
              <i className="fas fa-briefcase"></i>
              Gagner de l'argent
            </button>
            <div className="flex items-center gap-3 pl-6 border-l border-slate-200">
              <div className="text-right hidden lg:block">
                <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Client</p>
                <p className="text-xs font-bold text-slate-900">{userLocation ? 'Localisé' : 'Recherche...'}</p>
              </div>
              <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-all">
                <i className="fas fa-user"></i>
              </div>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-10">
        {/* Recherche intelligente */}
        <section className="mb-12 relative">
          <div className="max-w-2xl">
            <h2 className="text-4xl md:text-5xl font-black text-slate-900 mb-6 leading-tight">
              Réparations urgentes <br/>
              <span className="text-blue-600">autour de vous.</span>
            </h2>

            <div className="relative group">
              <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none text-slate-400 group-focus-within:text-blue-600 transition-colors">
                <i className="fas fa-search text-xl"></i>
              </div>
              <input 
                type="text" 
                placeholder="Ex: Ma serrure est bloquée à Douala..."
                className="block w-full pl-16 pr-36 py-6 bg-white border border-slate-200 rounded-3xl shadow-2xl shadow-slate-200/50 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-600 transition-all text-lg font-medium outline-none"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleAiDiagnose()}
              />
              <button 
                onClick={handleAiDiagnose}
                disabled={aiLoading}
                className="absolute right-3 top-3 bottom-3 bg-blue-600 text-white px-8 rounded-2xl font-black hover:bg-blue-700 transition-all flex items-center gap-2 shadow-lg shadow-blue-200"
              >
                {aiLoading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-magic"></i>}
                <span className="hidden sm:inline">Analyser</span>
              </button>
            </div>
          </div>
        </section>

        {/* Résultat IA */}
        {aiResult && (
          <div className="mb-10 p-8 bg-blue-600 text-white rounded-[2.5rem] shadow-2xl shadow-blue-200 animate-in fade-in slide-in-from-bottom-5 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-10"><i className="fas fa-robot text-[10rem] rotate-12"></i></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <span className="px-5 py-2 bg-white/20 backdrop-blur rounded-full text-xs font-black uppercase tracking-widest">Diagnostic IA</span>
                <span className={`px-5 py-2 rounded-full text-xs font-black uppercase tracking-widest ${aiResult.urgency === 'Haut' ? 'bg-orange-500' : 'bg-emerald-500'}`}>Urgence : {aiResult.urgency}</span>
              </div>
              <h3 className="text-3xl font-black mb-4 leading-tight">{aiResult.explanation}</h3>
              <p className="text-blue-100 font-medium text-lg mb-8 opacity-90">Expert suggéré : <span className="underline decoration-orange-400 decoration-2 font-bold">{CATEGORIES.find(c => c.id === aiResult.category)?.name}</span></p>
              <button onClick={() => setAiResult(null)} className="text-white/50 hover:text-white transition-colors text-sm font-bold">Effacer</button>
            </div>
          </div>
        )}

        {/* Filtres & Switch Vue */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-10">
          <div className="flex items-center gap-3 overflow-x-auto pb-4 w-full md:w-auto no-scrollbar">
            <button onClick={() => setSelectedCategory(null)} className={`whitespace-nowrap px-6 py-3 rounded-2xl text-sm font-black transition-all ${!selectedCategory ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'bg-white text-slate-500 border border-slate-200 hover:border-blue-200'}`}>Tous</button>
            {CATEGORIES.map(cat => (
              <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`whitespace-nowrap px-6 py-3 rounded-2xl text-sm font-black flex items-center gap-3 transition-all ${selectedCategory === cat.id ? 'bg-blue-600 text-white shadow-xl shadow-blue-200' : 'bg-white text-slate-500 border border-slate-200 hover:border-blue-200'}`}><i className={`fas ${cat.icon}`}></i>{cat.name}</button>
            ))}
          </div>

          <div className="flex bg-white p-1.5 rounded-2xl border border-slate-200 shadow-sm shrink-0">
            <button onClick={() => setViewMode('list')} className={`px-5 py-2.5 rounded-xl text-sm font-black flex items-center gap-2 transition-all ${viewMode === 'list' ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}><i className="fas fa-th-list"></i> Liste</button>
            <button onClick={() => setViewMode('map')} className={`px-5 py-2.5 rounded-xl text-sm font-black flex items-center gap-2 transition-all ${viewMode === 'map' ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}><i className="fas fa-map-marked-alt"></i> Carte</button>
          </div>
        </div>

        {/* Grille ou Carte */}
        {viewMode === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredWorkers.map(worker => (
              <div key={worker.id} className="bg-white rounded-[2.5rem] border border-slate-200 overflow-hidden hover:shadow-2xl hover:shadow-slate-200/50 hover:-translate-y-2 transition-all group cursor-pointer" onClick={() => setSelectedWorker(worker)}>
                <div className="p-8">
                  <div className="flex items-start justify-between mb-6">
                    <img src={worker.avatar} className="w-20 h-20 rounded-3xl object-cover ring-4 ring-slate-50 shadow-lg" alt={worker.name} />
                    <div className="text-right"><div className="text-2xl font-black text-slate-900">{worker.hourlyRate}€/h</div><div className="text-orange-500 font-black text-sm mt-1"><i className="fas fa-star"></i> {worker.rating}</div></div>
                  </div>
                  <h4 className="text-xl font-extrabold text-slate-900 mb-2 group-hover:text-blue-600 transition-colors">{worker.name}</h4>
                  <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mb-6">{CATEGORIES.find(c => c.id === worker.category)?.name} • {worker.experience} exp.</p>
                  <div className="flex items-center justify-between pt-6 border-t border-slate-100">
                    <div className="flex items-center gap-2 text-slate-500 text-xs font-bold truncate max-w-[150px]"><i className="fas fa-map-marker-alt text-blue-500"></i>{worker.location.address}</div>
                    <span className="text-blue-600 font-black text-xs uppercase">Détails</span>
                  </div>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="bg-white rounded-[3rem] h-[650px] relative overflow-hidden border-8 border-white shadow-2xl">
             <div ref={mapContainerRef} className="w-full h-full"></div>

             {/* Contrôles de carte flottants */}
             <div className="absolute top-6 right-6 z-[1000] flex flex-col gap-3">
                <button 
                  onClick={requestUserLocation}
                  disabled={locationLoading}
                  className="w-14 h-14 bg-white rounded-2xl shadow-2xl flex items-center justify-center text-blue-600 hover:bg-blue-50 active:scale-90 transition-all border border-slate-200 disabled:opacity-50"
                  title="Ma position réelle"
                >
                  <i className={`fas ${locationLoading ? 'fa-spinner animate-spin' : 'fa-crosshairs'} text-xl`}></i>
                </button>
             </div>

             {/* Message si non localisé */}
             {!userLocation && !locationLoading && (
               <div className="absolute top-6 left-1/2 -translate-x-1/2 z-[1000] bg-white px-6 py-3 rounded-2xl shadow-2xl border border-slate-100 text-sm font-bold flex items-center gap-3 animate-bounce">
                  <i className="fas fa-info-circle text-blue-500"></i>
                  Cliquez sur la cible pour nous permettre de vous localiser
               </div>
             )}

             <div className="absolute bottom-10 left-1/2 -translate-x-1/2 z-[1000] bg-slate-900/90 backdrop-blur-md px-8 py-4 rounded-3xl shadow-2xl text-white flex items-center gap-4">
               <div className="w-3 h-3 bg-blue-500 rounded-full animate-pulse shadow-[0_0_15px_rgba(37,99,235,0.8)]"></div>
               <span className="font-black text-sm uppercase tracking-widest">Experts à proximité</span>
             </div>
          </div>
        )}
      </main>

      {/* Modal Ajout Service */}
      {isProModalOpen && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center px-4 overflow-y-auto py-10">
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setIsProModalOpen(false)}></div>
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 duration-200 my-auto">
            <div className="p-10 border-b border-slate-100 bg-blue-600 text-white"><h3 className="text-3xl font-black mb-2">Devenir Partenaire</h3><p className="text-blue-100 font-medium">Partagez votre expertise avec la ville.</p></div>
            <form onSubmit={handleAddService} className="p-10 space-y-8 max-h-[65vh] overflow-y-auto no-scrollbar">
              <div className="flex flex-col items-center gap-4">
                <div onClick={() => fileInputRef.current?.click()} className="w-28 h-28 rounded-[2rem] bg-slate-100 border-4 border-dashed border-slate-300 flex items-center justify-center cursor-pointer overflow-hidden group hover:border-blue-600 shadow-inner">
                  {newWorker.avatar ? <img src={newWorker.avatar} className="w-full h-full object-cover" /> : <i className="fas fa-camera text-2xl text-slate-400 group-hover:text-blue-600"></i>}
                </div>
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" className="hidden" />
              </div>

              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Nom Complet" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold" value={newWorker.name} onChange={(e) => setNewWorker({...newWorker, name: e.target.value})} />
                <select className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" value={newWorker.category} onChange={(e) => setNewWorker({...newWorker, category: e.target.value})}>
                  {CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>

              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase tracking-widest px-1">Zone de service</label>
                <div className="relative">
                  <input required type="text" placeholder="Ville, Quartier..." className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 transition-all font-bold pr-40" value={newWorker.address} onBlur={handleManualAddressRefine} onChange={(e) => setNewWorker({...newWorker, address: e.target.value})} />
                  <button type="button" onClick={requestUserLocation} disabled={locationLoading} className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl text-[10px] font-black hover:bg-blue-700 transition-all">
                    {locationLoading ? <i className="fas fa-spinner animate-spin"></i> : "ICI"}
                  </button>
                </div>
              </div>

              <input required type="tel" placeholder="Téléphone" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" value={newWorker.phone} onChange={(e) => setNewWorker({...newWorker, phone: e.target.value})} />
              <button type="submit" className="w-full bg-orange-500 text-white py-6 rounded-[1.5rem] font-black text-lg shadow-2xl uppercase tracking-widest">Enregistrer mon profil</button>
            </form>
          </div>
        </div>
      )}

      {/* Détails Travailleur */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[3000] flex items-center justify-center px-4 overflow-y-auto">
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-2xl rounded-[3rem] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95 my-auto">
            <div className="h-48 bg-blue-600 relative overflow-hidden">
               <button onClick={() => setSelectedWorker(null)} className="absolute top-8 right-8 w-12 h-12 bg-white/20 backdrop-blur rounded-full flex items-center justify-center text-white"><i className="fas fa-times"></i></button>
               <div className="absolute -bottom-14 left-10 p-2 bg-white rounded-[2.5rem] shadow-2xl"><img src={selectedWorker.avatar} className="w-32 h-32 rounded-[2rem] object-cover" /></div>
            </div>
            <div className="pt-20 px-10 pb-10">
