                <div className="text-right"><div className="text-4xl font-black text-slate-900 leading-none mb-2">{selectedWorker.hourlyRate}€/h</div><div className="text-orange-500 font-black"><i className="fas fa-star"></i> {selectedWorker.rating}</div></div>
              </div>
              <div className="bg-slate-50 rounded-[2rem] p-8 border border-slate-100 text-center mb-10">
                  <h4 className="font-black text-slate-900 mb-2 uppercase text-xs">Localisation de l'expert</h4>
                  <p className="text-slate-500 font-bold mb-8 text-sm">{selectedWorker.location.address}</p>
                  <button onClick={() => { window.open(`https://www.google.com/maps/dir/?api=1&destination=${selectedWorker.location.lat},${selectedWorker.location.lng}`, '_blank'); }} className="w-full bg-white text-blue-600 border-2 border-blue-600 py-4 rounded-2xl font-black text-xs uppercase hover:bg-blue-50 flex items-center justify-center gap-2">
                    <i className="fas fa-directions"></i> Itinéraire complet (Google Maps)
                  </button>
                </div>
              <div className="flex gap-4">
                <button onClick={() => window.location.href = `tel:${selectedWorker.phone}`} className="flex-1 bg-slate-900 text-white py-6 rounded-3xl font-black text-lg flex items-center justify-center gap-4 shadow-2xl uppercase tracking-widest"><i className="fas fa-phone-alt"></i> Appeler</button>
                <button className="flex-1 bg-orange-500 text-white py-6 rounded-3xl font-black text-lg flex items-center justify-center gap-4 shadow-orange-100 uppercase tracking-widest"><i className="fas fa-comment-dots"></i> Message</button>
              </div>
            </div>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-slate-200 py-16 mt-20 text-center">
        <p className="text-slate-400 text-xs font-bold uppercase tracking-widest">© 2024 FixItNow Global</p>
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Global Leaflet

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);
  const [locationDenied, setLocationDenied] = useState(false);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const routeLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // New worker form state
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Attempt geolocation on start
  useEffect(() => {
    requestUserLocation(false); // Quietly try on load
  }, []);

  const requestUserLocation = (showErrors: boolean = true) => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const coords = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };
          setUserLocation(coords);
          setLocationDenied(false);
          setLocationLoading(false);
          // If in map mode, center it
          if (mapRef.current) {
            mapRef.current.flyTo([coords.lat, coords.lng], 14, { duration: 1.5 });
          } else {
            // Suggest switching to map to see self
            console.log("Localisé avec succès. Passez en vue carte pour vous voir.");
          }
        },
        (error) => {
          console.warn("Échec de localisation:", error.message);
          if (showErrors) {
            if (error.code === error.PERMISSION_DENIED) {
              setLocationDenied(true);
              alert("L'accès à la localisation a été refusé. Veuillez l'autoriser dans les réglages de votre navigateur ou saisir votre adresse manuellement.");
            } else {
              alert("Impossible de déterminer votre position. Veuillez réessayer ou saisir votre adresse.");
            }
          }
          setLocationLoading(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
      );
    } else {
      if (showErrors) alert("Votre navigateur ne supporte pas la géolocalisation.");
      setLocationLoading(false);
    }
  };

  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  // Map Initialization & Updates
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;

        const center = userLocation || { lat: 48.8566, lng: 2.3522 };

        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);

          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);

          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
          routeLayerRef.current = L.layerGroup().addTo(mapRef.current);
        } else {
          mapRef.current.invalidateSize();
        }

        markersLayerRef.current.clearLayers();

        // Add Workers
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar" alt="${worker.name}">`,
            iconSize: [44, 44],
            iconAnchor: [22, 22]
          });

          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => {
            setSelectedWorker(worker);
            drawRoute(worker);
          });
        });

        // Add User Marker (Distinct)
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-container',
            html: `<div class="user-location-pulse"><div class="user-location-dot"></div></div>`,
            iconSize: [30, 30],
            iconAnchor: [15, 15]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 })
           .addTo(markersLayerRef.current)
           .bindPopup("<div class='font-bold text-blue-600 text-center'>Vous êtes ici</div>");
        }
      }, 200);

      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, filteredWorkers]);

  const drawRoute = (worker: MaintenanceWorker) => {
    if (!userLocation || !routeLayerRef.current) return;
    routeLayerRef.current.clearLayers();

    const points = [
      [userLocation.lat, userLocation.lng],
      [worker.location.lat, worker.location.lng]
    ];

    L.polyline(points, {
      color: '#2563eb',
      weight: 5,
      opacity: 0.7,
      className: 'leaflet-interactive-path'
    }).addTo(routeLayerRef.current);

    // Auto zoom to show both
    const bounds = L.latLngBounds(points);
    mapRef.current.fitBounds(bounds, { padding: [50, 50] });
  };

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleAddService = (e: React.FormEvent) => {
    e.preventDefault();
    const lat = userLocation?.lat || (48.8566 + (Math.random() - 0.5) * 0.05);
    const lng = userLocation?.lng || (2.3522 + (Math.random() - 0.5) * 0.05);

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat, lng, address: newWorker.address || 'Adresse détectée' },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
    alert("Profil ajouté ! Vous êtes maintenant visible par les clients.");
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Alerte contextuelle si localisation refusée */}
      {locationDenied && (
        <div className="bg-orange-500 text-white px-6 py-4 flex items-center justify-between shadow-lg z-[2005] sticky top-0 animate-in slide-in-from-top duration-300">
          <div className="flex items-center gap-3">
            <i className="fas fa-location-dot text-xl animate-pulse"></i>
            <p className="font-bold text-sm">Géolocalisation refusée. Saisissez votre adresse manuellement pour trouver des experts proches.</p>
          </div>
          <button onClick={() => setLocationDenied(false)} className="bg-white/20 hover:bg-white/40 px-3 py-1 rounded-lg text-xs font-black uppercase">Fermer</button>
        </div>
      )}

      {/* Header Premium */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-slate-100 sticky top-0 z-[1001]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={resetFilters}>
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100 group-hover:scale-110 transition-transform">
              <i className="fas fa-tools text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">FixIt<span className="text-blue-600">Now</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Maintenance Intelligente</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-2xl font-extrabold shadow-lg shadow-orange-100 transition-all active:scale-95 flex items-center gap-2"
            >
              <i className="fas fa-briefcase"></i> Gagner de l'argent
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-all">
              <i className="fas fa-user"></i>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-10 lg:py-16">
        {/* Hero & Geolocation Button Section */}
        <section className="mb-16 relative">
          <div className="max-w-3xl">
            <h2 className="text-4xl md:text-6xl font-black text-slate-900 mb-6 leading-[1.1]">
              Un pépin technique ? <br/>
              <span className="text-blue-600 underline decoration-blue-100 decoration-8 underline-offset-4">Localisez une aide</span> maintenant.
            </h2>
            <p className="text-lg text-slate-500 font-medium mb-10 max-w-xl">
              Nouveau en ville ? Trouvez instantanément les experts les plus proches de votre position actuelle.
