            <button onClick={() => setViewMode('map')} className={`px-6 py-3 rounded-xl text-xs font-black flex items-center gap-2 transition-all uppercase tracking-widest ${viewMode === 'map' ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}><i className="fas fa-map-marked-alt"></i> Carte</button>
