              <div className="bg-slate-50 rounded-[2rem] p-8 border border-slate-100 mb-12">
                  <h4 className="font-black text-slate-400 mb-4 uppercase text-[10px] tracking-[0.2em] px-1">Zone d'intervention</h4>
                  <p className="text-slate-900 font-bold mb-8 text-lg flex items-center gap-3"><i className="fas fa-map-marker-alt text-blue-600"></i>{selectedWorker.location.address}</p>
                  <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                    <button onClick={() => { window.open(`https://www.google.com/maps/dir/?api=1&destination=${selectedWorker.location.lat},${selectedWorker.location.lng}`, '_blank'); }} className="bg-white text-blue-600 border-2 border-blue-600 py-4 rounded-2xl font-black text-xs uppercase hover:bg-blue-50 flex items-center justify-center gap-3 transition-all">
                      <i className="fas fa-directions"></i> Google Maps
                    </button>
                    {userLocation && viewMode === 'map' && (
                      <button onClick={() => { setSelectedWorker(selectedWorker); drawRoute(selectedWorker); setSelectedWorker(null); }} className="bg-blue-600 text-white py-4 rounded-2xl font-black text-xs uppercase hover:bg-blue-700 flex items-center justify-center gap-3 transition-all">
                        <i className="fas fa-route"></i> Voir l'itinéraire
                      </button>
                    )}
                  </div>
              </div>

              <div className="flex gap-4">
                <button onClick={() => window.location.href = `tel:${selectedWorker.phone}`} className="flex-1 bg-slate-900 text-white py-6 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-4 hover:bg-slate-800 shadow-2xl uppercase tracking-widest transition-all active:scale-95"><i className="fas fa-phone-alt"></i> Appeler</button>
                <button className="flex-1 bg-orange-500 text-white py-6 rounded-[1.5rem] font-black text-lg flex items-center justify-center gap-4 shadow-xl shadow-orange-100 uppercase tracking-widest transition-all active:scale-95"><i className="fas fa-comment-dots"></i> Message</button>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Footer Minimal */}
      <footer className="bg-white border-t border-slate-100 py-16 mt-20 text-center">
        <div className="max-w-7xl mx-auto px-4">
          <div className="flex items-center justify-center gap-3 mb-8">
            <div className="w-8 h-8 bg-blue-600 rounded-xl flex items-center justify-center text-white"><i className="fas fa-tools"></i></div>
            <span className="text-lg font-black tracking-tighter">FixItNow</span>
          </div>
          <p className="text-slate-400 text-[10px] font-black uppercase tracking-[0.4em]">Trouvez l'aide. Restez serein.</p>
        </div>
      </footer>

      {/* Register Service Modal */}
      {isProModalOpen && (
        <div className="fixed inset-0 z-[2000] flex items-center justify-center px-4 overflow-y-auto py-10">
          <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-xl" onClick={() => setIsProModalOpen(false)}></div>
          <div className="bg-white w-full max-w-xl rounded-[3rem] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95">
            <div className="p-10 border-b border-slate-50 bg-blue-600 text-white relative">
              <h3 className="text-3xl font-black mb-2">Rejoindre le réseau</h3>
              <p className="text-blue-100 font-medium opacity-80">Rendez vos services visibles à vos voisins.</p>
              <button onClick={() => setIsProModalOpen(false)} className="absolute top-8 right-8 text-white/50 hover:text-white"><i className="fas fa-times text-xl"></i></button>
            </div>
            <form onSubmit={handleAddService} className="p-10 space-y-6 max-h-[65vh] overflow-y-auto no-scrollbar">
               <div className="flex flex-col items-center gap-4 mb-4">
                <div onClick={() => fileInputRef.current?.click()} className="w-28 h-28 rounded-[2rem] bg-slate-100 border-4 border-dashed border-slate-300 flex items-center justify-center cursor-pointer overflow-hidden hover:border-blue-600 transition-all">
                  {newWorker.avatar ? <img src={newWorker.avatar} className="w-full h-full object-cover" alt="" /> : <i className="fas fa-camera text-2xl text-slate-300"></i>}
                </div>
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} accept="image/*" className="hidden" />
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                <input required type="text" placeholder="Nom Complet" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" value={newWorker.name} onChange={(e) => setNewWorker({...newWorker, name: e.target.value})} />
                <select className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" value={newWorker.category} onChange={(e) => setNewWorker({...newWorker, category: e.target.value})}>
                  {CATEGORIES.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <div className="relative">
                  <input required type="text" placeholder="Ville, Quartier..." className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold pr-32" value={newWorker.address} onChange={(e) => setNewWorker({...newWorker, address: e.target.value})} />
                  <button type="button" onClick={() => requestUserLocation(true)} className="absolute right-2 top-2 bottom-2 bg-blue-600 text-white px-4 rounded-xl text-[10px] font-black uppercase tracking-widest">Ma Position</button>
                </div>
              </div>
              <input required type="tel" placeholder="Téléphone (ex: +33...)" className="w-full px-6 py-4 bg-slate-50 border-2 border-slate-100 rounded-2xl outline-none focus:border-blue-600 font-bold" value={newWorker.phone} onChange={(e) => setNewWorker({...newWorker, phone: e.target.value})} />
              <button type="submit" className="w-full bg-orange-500 text-white py-6 rounded-[1.5rem] font-black text-lg shadow-xl uppercase tracking-widest transition-all active:scale-95">Publier mon profil</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Global Leaflet

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'list' | 'map'>('list');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);
  const [locationDenied, setLocationDenied] = useState(false);
  const [manualLocation, setManualLocation] = useState('');

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const routeLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // New worker form state
  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  // Attempt geolocation on start
  useEffect(() => {
    requestUserLocation(false); 
  }, []);

  const requestUserLocation = (showErrors: boolean = true) => {
    setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const coords = {
            lat: position.coords.latitude,
            lng: position.coords.longitude
          };
          setUserLocation(coords);
          setLocationDenied(false);
          setLocationLoading(false);

          // Automatically zoom and center
          if (mapRef.current) {
            mapRef.current.flyTo([coords.lat, coords.lng], 15, { 
              duration: 2,
              easeLinearity: 0.25 
            });
          }
        },
        (error) => {
          console.warn("Échec de localisation:", error.message);
          if (error.code === error.PERMISSION_DENIED) {
            setLocationDenied(true);
          } else if (showErrors) {
            alert("Impossible de déterminer votre position. Veuillez réessayer ou saisir votre adresse.");
          }
          setLocationLoading(false);
        },
        { enableHighAccuracy: true, timeout: 10000 }
      );
    } else {
      if (showErrors) alert("Votre navigateur ne supporte pas la géolocalisation.");
      setLocationLoading(false);
    }
  };

  const handleManualLocationSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!manualLocation.trim()) return;

    setLocationLoading(true);
    try {
      const refined = await refineLocation(manualLocation);
      // For demo purposes, we update the placeholder address and dismiss the denial banner
      // In a real app, we would geocode this 'refined' string to get lat/lng
      console.log("Location saisie manuellement :", refined);
      setLocationDenied(false);
      setSearchQuery(prev => prev || `À ${refined}`);
    } catch (e) {
      console.error(e);
    } finally {
      setLocationLoading(false);
    }
  };

  const resetFilters = () => {
    setSelectedCategory(null);
    setSearchQuery('');
    setAiResult(null);
  };

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchQuery, workers]);

  // Map Initialization & Updates
  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;

        const center = userLocation || { lat: 48.8566, lng: 2.3522 };

        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);

          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);

          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
          routeLayerRef.current = L.layerGroup().addTo(mapRef.current);
        } else {
          mapRef.current.invalidateSize();
        }

        markersLayerRef.current.clearLayers();

        // Add Workers
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar" alt="${worker.name}">`,
            iconSize: [44, 44],
            iconAnchor: [22, 22]
          });

          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => {
            setSelectedWorker(worker);
            drawRoute(worker);
          });
        });

        // Add User Marker (Distinctive core and pulse)
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-wrapper',
            html: `<div class="user-marker-pulse"></div><div class="user-marker-core"></div>`,
            iconSize: [40, 40],
            iconAnchor: [20, 20]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 })
           .addTo(markersLayerRef.current)
           .bindPopup("<div class='font-bold text-blue-600 text-center'>Votre position actuelle</div>");
        }
      }, 200);

      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, filteredWorkers]);

  const drawRoute = (worker: MaintenanceWorker) => {
    if (!userLocation || !routeLayerRef.current) return;
    routeLayerRef.current.clearLayers();

    const points = [
      [userLocation.lat, userLocation.lng],
      [worker.location.lat, worker.location.lng]
    ];

    L.polyline(points, {
      color: '#2563eb',
      weight: 5,
      opacity: 0.7,
      className: 'leaflet-interactive-path'
    }).addTo(routeLayerRef.current);

    const bounds = L.latLngBounds(points);
    mapRef.current.fitBounds(bounds, { padding: [50, 50] });
  };

  const handleAiDiagnose = async () => {
    if (!searchQuery.trim()) return;
    setAiLoading(true);
    try {
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
    } catch (e) { console.error(e); } finally { setAiLoading(false); }
  };

  const handleAddService = (e: React.FormEvent) => {
    e.preventDefault();
    const lat = userLocation?.lat || (48.8566 + (Math.random() - 0.5) * 0.05);
    const lng = userLocation?.lng || (2.3522 + (Math.random() - 0.5) * 0.05);

    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat, lng, address: newWorker.address || 'Adresse détectée' },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    setNewWorker({ name: '', category: 'general', experience: '', hourlyRate: '', phone: '', skills: '', address: '', avatar: '' });
    alert("Profil ajouté !");
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col font-sans selection:bg-blue-100 selection:text-blue-900">
      {/* Bannière de géolocalisation persistante si refusée */}
      {locationDenied && (
        <div className="bg-slate-900 text-white px-6 py-6 shadow-2xl z-[2005] sticky top-0 border-b border-blue-500/30">
          <div className="max-w-7xl mx-auto flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="flex items-start gap-4">
              <div className="w-12 h-12 bg-blue-600/20 rounded-2xl flex items-center justify-center shrink-0">
                <i className="fas fa-location-arrow text-blue-500 text-xl"></i>
              </div>
              <div>
                <p className="font-black text-lg leading-tight mb-1">Localisation désactivée</p>
                <p className="text-slate-400 text-sm font-medium">Nous ne pouvons pas vous situer. Saisissez votre position manuellement ou réessayez.</p>
              </div>
            </div>

            <form onSubmit={handleManualLocationSubmit} className="flex-1 w-full max-w-lg flex gap-2">
               <input 
                type="text" 
                placeholder="Entrez votre ville ou quartier..."
                className="flex-1 px-5 py-3 bg-white/10 border border-white/20 rounded-xl outline-none focus:border-blue-500 transition-all font-bold text-sm"
                value={manualLocation}
                onChange={(e) => setManualLocation(e.target.value)}
               />
               <button type="submit" className="bg-blue-600 px-6 py-3 rounded-xl font-black text-xs uppercase tracking-widest hover:bg-blue-700">Valider</button>
            </form>

            <div className="flex items-center gap-4">
              <button onClick={() => requestUserLocation(true)} className="text-blue-400 font-black text-xs uppercase tracking-widest hover:text-blue-300">Réessayer</button>
              <button onClick={() => setLocationDenied(false)} className="w-10 h-10 flex items-center justify-center rounded-xl bg-white/5 hover:bg-white/10 transition-all"><i className="fas fa-times"></i></button>
            </div>
          </div>
        </div>
      )}

      {/* Header Premium */}
      <header className="bg-white/80 backdrop-blur-xl border-b border-slate-100 sticky top-0 z-[1001]">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-3 cursor-pointer group" onClick={resetFilters}>
            <div className="w-12 h-12 bg-blue-600 rounded-2xl flex items-center justify-center text-white shadow-xl shadow-blue-100 group-hover:scale-110 transition-transform">
              <i className="fas fa-tools text-2xl"></i>
            </div>
            <div>
              <h1 className="text-2xl font-black tracking-tighter text-slate-900 leading-none">FixIt<span className="text-blue-600">Now</span></h1>
              <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">Maintenance Intelligente</p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
            <button 
              onClick={() => setIsProModalOpen(true)}
              className="bg-orange-500 hover:bg-orange-600 text-white px-6 py-3 rounded-2xl font-extrabold shadow-lg shadow-orange-100 transition-all active:scale-95 flex items-center gap-2"
            >
              <i className="fas fa-briefcase"></i> Gagner de l'argent
            </button>
            <div className="w-10 h-10 rounded-full bg-slate-100 border border-slate-200 flex items-center justify-center text-slate-400 cursor-pointer hover:bg-slate-200 transition-all">
              <i className="fas fa-user"></i>
            </div>
          </div>
        </div>
      </header>

      <main className="flex-1 max-w-7xl mx-auto w-full px-4 sm:px-6 py-10 lg:py-16">
        {/* Hero & Geolocation Button Section */}
        <section className="mb-16 relative">
          <div className="max-w-3xl">
            <h2 className="text-4xl md:text-6xl font-black text-slate-900 mb-6 leading-[1.1]">
              Un pépin technique ? <br/>
              <span className="text-blue-600 underline decoration-blue-100 decoration-8 underline-offset-4">Localisez une aide</span> maintenant.
            </h2>
            <p className="text-lg text-slate-500 font-medium mb-10 max-w-xl">
              Nouveau en ville ? Activez votre position pour voir instantanément les experts les plus proches.
            </p>

            <div className="flex flex-col sm:flex-row gap-4 max-w-2xl">
              <div className="relative flex-1 group">
                <div className="absolute inset-y-0 left-0 pl-6 flex items-center pointer-events-none text-slate-400 group-focus-within:text-blue-600 transition-colors">
                  <i className="fas fa-search"></i>
                </div>
                <input 
                  type="text" 
                  placeholder="Ex: Mon évier déborde..."
                  className="block w-full pl-14 pr-4 py-5 bg-white border border-slate-200 rounded-2xl shadow-xl shadow-slate-200/50 focus:ring-4 focus:ring-blue-500/10 focus:border-blue-600 transition-all text-base font-medium outline-none"
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && handleAiDiagnose()}
                />
              </div>
              <button 
                onClick={handleAiDiagnose}
                disabled={aiLoading}
                className="bg-blue-600 text-white px-10 py-5 rounded-2xl font-black hover:bg-blue-700 transition-all flex items-center justify-center gap-3 shadow-xl shadow-blue-100 active:scale-95 disabled:opacity-50"
              >
                {aiLoading ? <i className="fas fa-spinner animate-spin"></i> : <i className="fas fa-bolt"></i>}
                Analyser
              </button>
              <button 
                onClick={() => requestUserLocation(true)}
                disabled={locationLoading}
                className="bg-white border-2 border-blue-600 text-blue-600 px-6 py-5 rounded-2xl font-black hover:bg-blue-50 transition-all flex items-center justify-center gap-3 shadow-lg active:scale-95 disabled:opacity-50"
                title="Détecter ma position exacte"
              >
                <i className={`fas ${locationLoading ? 'fa-circle-notch animate-spin' : 'fa-location-arrow'}`}></i>
                <span className="sm:hidden lg:inline">Ma Position</span>
              </button>
            </div>
          </div>
        </section>

        {/* AI Results */}
        {aiResult && (
          <div className="mb-12 p-8 bg-blue-600 text-white rounded-[2.5rem] shadow-2xl animate-in zoom-in-95 duration-300 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-10 opacity-10"><i className="fas fa-robot text-[10rem] rotate-12"></i></div>
            <div className="relative z-10">
              <div className="flex items-center gap-4 mb-6">
                <span className="px-4 py-1 bg-white/20 backdrop-blur rounded-full text-[10px] font-black uppercase tracking-widest">Diagnostic FixIt</span>
                <span className={`px-4 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${aiResult.urgency === 'Haut' ? 'bg-orange-500' : 'bg-emerald-500'}`}>Urgence : {aiResult.urgency}</span>
              </div>
              <h3 className="text-3xl font-black mb-4 leading-tight">{aiResult.explanation}</h3>
              <button onClick={() => setAiResult(null)} className="text-white/60 hover:text-white font-bold text-xs uppercase underline">Fermer</button>
            </div>
          </div>
        )}

        {/* Filters & View Switcher */}
        <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-12">
          <div className="flex items-center gap-3 overflow-x-auto pb-4 w-full md:w-auto no-scrollbar">
            <button onClick={() => setSelectedCategory(null)} className={`whitespace-nowrap px-6 py-3 rounded-2xl text-xs font-black transition-all uppercase tracking-widest ${!selectedCategory ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-white text-slate-500 border border-slate-200 hover:border-blue-200'}`}>Tous</button>
            {CATEGORIES.map(cat => (
              <button key={cat.id} onClick={() => setSelectedCategory(cat.id)} className={`whitespace-nowrap px-6 py-3 rounded-2xl text-xs font-black flex items-center gap-3 transition-all uppercase tracking-widest ${selectedCategory === cat.id ? 'bg-blue-600 text-white shadow-xl shadow-blue-100' : 'bg-white text-slate-500 border border-slate-200 hover:border-blue-200'}`}><i className={`fas ${cat.icon}`}></i>{cat.name}</button>
            ))}
          </div>

          <div className="flex bg-white p-2 rounded-2xl border border-slate-100 shadow-sm shrink-0">
            <button onClick={() => setViewMode('list')} className={`px-6 py-3 rounded-xl text-xs font-black flex items-center gap-2 transition-all uppercase tracking-widest ${viewMode === 'list' ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}><i className="fas fa-list"></i> Liste</button>
            <button onClick={() => setViewMode('map')} className={`px-6 py-3 rounded-xl text-xs font-black flex items-center gap-2 transition-all uppercase tracking-widest ${viewMode === 'map' ? 'bg-blue-50 text-blue-600' : 'text-slate-400'}`}><i className="fas fa-map-marked-alt"></i> Carte</button>
          </div>
        </div>

        {/* Content Section */}
        {viewMode === 'list' ? (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
            {filteredWorkers.map(worker => (
              <div key={worker.id} className="bg-white rounded-[2.5rem] border border-slate-100 overflow-hidden hover:shadow-2xl hover:shadow-slate-200/50 hover:-translate-y-2 transition-all group cursor-pointer" onClick={() => setSelectedWorker(worker)}>
                <div className="p-8">
                  <div className="flex items-start justify-between mb-8">
                    <div className="relative">
                      <img src={worker.avatar} className="w-20 h-20 rounded-3xl object-cover ring-4 ring-slate-50" alt={worker.name} />
                      <div className="absolute -bottom-2 -right-2 w-6 h-6 bg-emerald-500 border-4 border-white rounded-full"></div>
                    </div>
                    <div className="text-right">
                      <div className="text-3xl font-black text-slate-900">{worker.hourlyRate}€<span className="text-xs text-slate-400">/h</span></div>
