      )}

      {/* Footer Minimal */}
      <footer className="bg-white border-t border-slate-100 py-16 mt-20 text-center">
        <div className="max-w-7xl mx-auto px-4 text-slate-300">
           <p className="text-[10px] font-black uppercase tracking-[0.4em]">FixItNow • Service de Proximité</p>
        </div>
      </footer>

      {/* Register Service Modal */}
      {isProModalOpen && (
