          <div className="bg-white w-full max-w-xl rounded-[3rem] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95">
            <div className="p-10 border-b border-slate-50 bg-blue-600 text-white relative">
              <h3 className="text-3xl font-black mb-2">Rejoindre le réseau</h3>
              <p className="text-blue-100 font-medium opacity-80">Devenez visible pour vos futurs clients.</p>
