            <form onSubmit={handleAddService} className="p-10 space-y-6 max-h-[65vh] overflow-y-auto no-scrollbar">
               <div className="flex flex-col items-center gap-4 mb-4">
                <div onClick={() => fileInputRef.current?.click()} className="w-28 h-28 rounded-[2rem] bg-slate-100 border-4 border-dashed border-slate-300 flex items-center justify-center cursor-pointer overflow-hidden hover:border-blue-600 transition-all">
