  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [cityQuery, setCityQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'landing' | 'list' | 'map'>('landing');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  const requestUserLocation = (silent: boolean = false) => {
    if (!silent) setLocationLoading(true);
    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const coords = { lat: position.coords.latitude, lng: position.coords.longitude };
          setUserLocation(coords);
          setLocationLoading(false);
          if (mapRef.current) mapRef.current.flyTo([coords.lat, coords.lng], 15);
        },
        () => setLocationLoading(false),
        { enableHighAccuracy: true, timeout: 5000 }
      );
    }
  };

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesCity = cityQuery ? worker.location.address.toLowerCase().includes(cityQuery.toLowerCase()) : true;
      return matchesCategory && matchesSearch && matchesCity;
    });
  }, [selectedCategory, searchQuery, cityQuery, workers]);

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;
        const center = userLocation || { lat: 4.0511, lng: 9.7679 }; // Douala par défaut
        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);
          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);
          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
        }
        markersLayerRef.current.clearLayers();
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar">`,
            iconSize: [44, 44],
            iconAnchor: [22, 22]
          });
          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => setSelectedWorker(worker));
        });
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-wrapper',
            html: `<div class="user-marker-pulse"></div><div class="user-marker-core"></div>`,
            iconSize: [40, 40],
            iconAnchor: [20, 20]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 }).addTo(markersLayerRef.current);
        }
      }, 100);
      return () => clearTimeout(timer);
    }
  }, [viewMode, userLocation, filteredWorkers]);

  const handleSearch = async () => {
    if (searchQuery.length > 5) {
      setAiLoading(true);
      const result = await diagnoseIssue(searchQuery);
      if (result) {
        setAiResult(result);
        setSelectedCategory(result.category);
      }
      setAiLoading(false);
    }
    setViewMode('list');
  };

  const handleAddService = (e: React.FormEvent) => {
    e.preventDefault();
    const worker: MaintenanceWorker = {
      id: Date.now().toString(),
      name: newWorker.name,
      category: newWorker.category,
      rating: 5.0,
      reviews: 0,
      experience: newWorker.experience,
      hourlyRate: parseFloat(newWorker.hourlyRate) || 0,
      status: 'online',
      location: { lat: 4.0511, lng: 9.7679, address: newWorker.address },
      phone: newWorker.phone,
      avatar: newWorker.avatar || `https://picsum.photos/seed/${newWorker.name}/200`,
      skills: newWorker.skills.split(',').map(s => s.trim())
    };
    setWorkers([worker, ...workers]);
    setIsProModalOpen(false);
    alert("Votre profil a été créé !");
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setNewWorker(prev => ({ ...prev, avatar: reader.result as string }));
      reader.readAsDataURL(file);
    }
  };

  return (
    <div className="min-h-screen bg-white">
      {/* HEADER */}
      <nav className="border-b border-slate-100 bg-white sticky top-0 z-[1001]">
        <div className="max-w-7xl mx-auto px-6 h-20 flex items-center justify-between">
          <div className="flex items-center gap-8">
            <div className="flex items-center gap-2 cursor-pointer" onClick={() => setViewMode('landing')}>
              <div className="w-10 h-10 bg-blue-700 rounded-xl flex items-center justify-center text-white">
                <i className="fas fa-wrench"></i>
              </div>
              <span className="text-2xl font-black text-slate-800 tracking-tight">
                Maintenance<span className="text-orange-600">Connect</span>
              </span>
            </div>
            <div className="hidden lg:flex items-center gap-6 text-slate-500 font-semibold text-sm">
              <button onClick={() => setViewMode('list')} className="hover:text-blue-700">Trouver un pro</button>
              <a href="#" className="hover:text-blue-700">Comment ça marche</a>
              <button onClick={() => setIsProModalOpen(true)} className="hover:text-blue-700">Devenir maintenancier</button>
            </div>
          </div>
          <div className="flex items-center gap-4">
            <button className="flex items-center gap-2 text-slate-700 font-bold text-sm px-4 py-2 hover:bg-slate-50 rounded-lg">
              <i className="fas fa-sign-in-alt"></i> Connexion
            </button>
            <button className="bg-blue-700 text-white px-6 py-3 rounded-xl font-bold text-sm flex items-center gap-2 shadow-lg shadow-blue-100 hover:bg-blue-800 transition-all">
              <i className="fas fa-user-plus"></i> Inscription
            </button>
          </div>
        </div>
      </nav>

      {viewMode === 'landing' ? (
        <>
          {/* HERO SECTION */}
          <section className="relative pt-20 pb-32 overflow-hidden bg-slate-50/50">
            <div className="max-w-5xl mx-auto px-6 text-center relative z-10">
              <div className="inline-flex items-center gap-2 bg-orange-100 text-orange-700 px-4 py-2 rounded-full text-xs font-bold mb-10">
                <i className="far fa-clock"></i> Service d'urgence disponible 24h/24 au Cameroun
              </div>
              <h1 className="text-5xl md:text-7xl font-black text-slate-900 mb-8 leading-tight tracking-tight">
                Trouvez un <span className="gradient-text">maintenancier</span><br/> près de chez vous
              </h1>
              <p className="text-lg text-slate-500 font-medium mb-12 max-w-3xl mx-auto leading-relaxed">
                Plombiers, électriciens, froid, informaticiens... Connectez-vous instantanément aux meilleurs professionnels de Douala, Yaoundé et partout au Cameroun.
              </p>

              {/* RECHERCHE BAR - CORRECTION DES FONDS NOIRS */}
              <div className="bg-white p-2 rounded-2xl shadow-2xl flex flex-col md:flex-row gap-2 border border-slate-100 max-w-4xl mx-auto mb-16 relative overflow-hidden">
                <div className="flex-1 flex items-center px-4 gap-3 border-b md:border-b-0 md:border-r border-slate-100 py-4 md:py-0 bg-white">
                  <i className="fas fa-search text-blue-500"></i>
                  <input 
                    type="text" 
                    placeholder="Que recherchez-vous ? (clim, électricité...)" 
                    className="w-full outline-none font-semibold text-slate-700 bg-white placeholder:text-slate-400"
                    style={{ background: 'white' }}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                  />
                </div>
                <div className="flex-1 flex items-center px-4 gap-3 py-4 md:py-0 bg-white">
                  <i className="fas fa-map-marker-alt text-blue-500"></i>
                  <input 
                    type="text" 
                    placeholder="Votre ville (ex: Douala, Yaoundé...)" 
                    className="w-full outline-none font-semibold text-slate-700 bg-white placeholder:text-slate-400"
                    style={{ background: 'white' }}
                    value={cityQuery}
                    onChange={(e) => setCityQuery(e.target.value)}
                  />
                </div>
                <button 
                  onClick={handleSearch}
                  className="bg-blue-700 text-white px-10 py-4 rounded-xl font-bold hover:bg-blue-800 shadow-xl shadow-blue-100 transition-all active:scale-95"
                >
                  Rechercher
                </button>
              </div>

              {/* STATS */}
              <div className="grid grid-cols-2 md:grid-cols-4 gap-8 max-w-4xl mx-auto">
                <div>
                  <div className="text-4xl font-black text-blue-700">500+</div>
                  <div className="text-slate-400 font-bold text-xs uppercase tracking-widest">Maintenanciers</div>
                </div>
                <div>
                  <div className="text-4xl font-black text-blue-700">10k+</div>
                  <div className="text-slate-400 font-bold text-xs uppercase tracking-widest">Interventions</div>
                </div>
                <div>
                  <div className="text-4xl font-black text-blue-700">4.8/5</div>
                  <div className="text-slate-400 font-bold text-xs uppercase tracking-widest">Satisfaction</div>
                </div>
                <div>
                  <div className="text-4xl font-black text-blue-700">&lt;30min</div>
                  <div className="text-slate-400 font-bold text-xs uppercase tracking-widest">Délai d'arrivée</div>
                </div>
              </div>
            </div>
          </section>

          {/* CATEGORIES SECTION */}
          <section className="py-24 max-w-7xl mx-auto px-6">
            <div className="text-center mb-16">
              <h2 className="text-3xl font-black text-slate-900 mb-2">Nos catégories au Cameroun</h2>
              <p className="text-slate-500 font-medium">Découvrez les services les plus demandés dans nos villes.</p>
            </div>
            <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-6 gap-6">
              {CATEGORIES.map(cat => (
                <div 
                  key={cat.id} 
                  onClick={() => { setSelectedCategory(cat.id); setViewMode('list'); }}
                  className="bg-white border border-slate-100 p-8 rounded-2xl flex flex-col items-center text-center hover:shadow-xl hover:border-blue-200 cursor-pointer transition-all"
                >
                  <div className="w-14 h-14 bg-blue-50 rounded-xl flex items-center justify-center text-blue-700 text-xl mb-4">
                    <i className={`fas ${cat.icon}`}></i>
                  </div>
                  <h3 className="font-bold text-slate-900 mb-1">{cat.name}</h3>
                </div>
              ))}
            </div>
          </section>

          {/* RECOMMENDED WORKERS */}
          <section className="py-24 bg-slate-50/30">
            <div className="max-w-7xl mx-auto px-6">
              <div className="flex items-end justify-between mb-12">
                <div>
                  <h2 className="text-3xl font-black text-slate-900 mb-2">Les mieux notés à proximité</h2>
                  <p className="text-slate-500 font-medium">Des experts de confiance recommandés par les Camerounais.</p>
                </div>
                <button onClick={() => setViewMode('list')} className="text-blue-700 font-bold text-sm flex items-center gap-2 hover:underline">
                  Voir tout <i className="fas fa-arrow-right"></i>
                </button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                {workers.slice(0, 4).map(worker => (
                  <div key={worker.id} className="bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm hover:shadow-xl transition-all group">
                    <div className="relative h-48">
                      <img src={worker.avatar} className="w-full h-full object-cover" alt="" />
                      <div className="absolute top-4 right-4 bg-emerald-100 text-emerald-700 px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2">
                        <div className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></div> Disponible
                      </div>
                    </div>
                    <div className="p-6">
                      <div className="flex items-center justify-between mb-2">
                        <h4 className="font-black text-slate-900">{worker.name}</h4>
                        <div className="text-orange-500 font-black text-xs">
                          <i className="fas fa-star"></i> {worker.rating}
                        </div>
                      </div>
                      <div className="flex items-center gap-2 text-slate-400 text-xs font-bold mb-6">
                        <i className="fas fa-map-marker-alt text-blue-700"></i> {worker.location.address}
                      </div>
                      <div className="flex items-center justify-between pt-4 border-t border-slate-50">
                        <div className="text-slate-400 text-[10px] font-bold uppercase tracking-widest">
                          {worker.experience} exp.
                        </div>
                        <div className="text-blue-700 font-black text-lg">
                          {worker.hourlyRate.toLocaleString()} <span className="text-[10px] text-slate-300">FCFA/h</span>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </section>

          {/* FOOTER */}
          <footer className="bg-slate-950 text-white py-24">
            <div className="max-w-7xl mx-auto px-6 grid grid-cols-1 md:grid-cols-4 gap-12 mb-20">
              <div className="col-span-1 md:col-span-1">
                <div className="flex items-center gap-2 mb-8">
                  <div className="w-8 h-8 bg-blue-700 rounded-lg flex items-center justify-center text-white">
                    <i className="fas fa-wrench"></i>
                  </div>
                  <span className="text-xl font-black tracking-tight">Maintenance<span className="text-orange-600">Connect</span></span>
                </div>
                <p className="text-slate-500 text-sm font-medium leading-relaxed">Le réseau numéro 1 de maintenance au Cameroun.</p>
              </div>
              <div>
                <h4 className="font-black text-xs uppercase tracking-widest mb-8">Villes</h4>
                <ul className="space-y-4 text-sm text-slate-500 font-bold">
                  <li><a href="#" className="hover:text-white transition-all">Douala</a></li>
                  <li><a href="#" className="hover:text-white transition-all">Yaoundé</a></li>
                  <li><a href="#" className="hover:text-white transition-all">Bafoussam</a></li>
                  <li><a href="#" className="hover:text-white transition-all">Garoua</a></li>
                </ul>
              </div>
              <div>
                <h4 className="font-black text-xs uppercase tracking-widest mb-8">Légales</h4>
                <ul className="space-y-4 text-sm text-slate-500 font-bold">
                  <li><a href="#" className="hover:text-white transition-all">CGU</a></li>
                  <li><a href="#" className="hover:text-white transition-all">Devenir Partenaire</a></li>
                </ul>
              </div>
              <div>
                <h4 className="font-black text-xs uppercase tracking-widest mb-8">Contact</h4>
                <p className="text-slate-500 text-sm font-bold">Yaoundé, Bastos</p>
                <p className="text-slate-500 text-sm font-bold">+237 600 00 00 00</p>
              </div>
            </div>
            <div className="max-w-7xl mx-auto px-6 pt-12 border-t border-slate-900 text-center text-slate-600 text-[10px] font-black uppercase tracking-[0.3em]">
              © 2024 MaintenanceConnect Cameroun.
            </div>
          </footer>
        </>
      ) : (
        <main className="max-w-7xl mx-auto px-6 py-12">
          {/* VUE RESULTATS */}
          <div className="flex flex-col md:flex-row items-center justify-between gap-6 mb-12">
            <div>
              <button 
                onClick={() => setViewMode('landing')}
                className="text-slate-400 font-bold text-xs uppercase flex items-center gap-2 mb-4 hover:text-blue-700"
              >
                <i className="fas fa-arrow-left"></i> Retour
              </button>
              <h2 className="text-3xl font-black text-slate-900">
                {selectedCategory ? CATEGORIES.find(c => c.id === selectedCategory)?.name : "Tous les pros"}
                {cityQuery && <span className="text-blue-700"> à {cityQuery}</span>}
              </h2>
            </div>
            <div className="flex bg-slate-100 p-1 rounded-2xl">
              <button onClick={() => setViewMode('list')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${viewMode === 'list' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-400'}`}>Liste</button>
              <button onClick={() => setViewMode('map')} className={`px-6 py-2.5 rounded-xl text-[10px] font-black uppercase tracking-widest ${viewMode === 'map' ? 'bg-white text-blue-700 shadow-sm' : 'text-slate-400'}`}>Carte</button>
            </div>
          </div>

          {viewMode === 'list' ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
              {filteredWorkers.map(worker => (
                <div key={worker.id} className="bg-white rounded-[2rem] border border-slate-100 overflow-hidden hover:shadow-2xl transition-all cursor-pointer" onClick={() => setSelectedWorker(worker)}>
                  <div className="p-8">
                    <div className="flex items-start justify-between mb-8">
                      <img src={worker.avatar} className="w-16 h-16 rounded-2xl object-cover" alt="" />
                      <div className="text-right">
                        <div className="text-xl font-black text-slate-900">{worker.hourlyRate.toLocaleString()} <span className="text-xs text-slate-300">FCFA</span></div>
                        <div className="text-orange-500 font-black text-sm"><i className="fas fa-star"></i> {worker.rating}</div>
                      </div>
                    </div>
                    <h4 className="text-lg font-black text-slate-900 mb-1">{worker.name}</h4>
                    <p className="text-slate-400 font-bold text-[10px] uppercase tracking-widest">{worker.location.address}</p>
                  </div>
                </div>
              ))}
            </div>
          ) : (
            <div className="bg-white rounded-[2rem] h-[600px] border border-slate-100 shadow-2xl overflow-hidden relative">
               <div ref={mapContainerRef} className="w-full h-full"></div>
            </div>
          )}
        </main>
      )}

      {/* MODAL DETAILS */}
      {selectedWorker && (
        <div className="fixed inset-0 z-[4000] flex items-center justify-center px-4">
          <div className="fixed inset-0 bg-slate-950/80 backdrop-blur-sm" onClick={() => setSelectedWorker(null)}></div>
          <div className="bg-white w-full max-w-xl rounded-[2.5rem] overflow-hidden shadow-2xl relative z-10 animate-in zoom-in-95">
            <div className="p-10 bg-blue-700 text-white">
              <h3 className="text-3xl font-black">{selectedWorker.name}</h3>
              <p className="text-blue-100 font-bold uppercase text-[10px] tracking-widest">{selectedWorker.location.address}</p>
            </div>
            <div className="p-10">
               <div className="text-4xl font-black text-slate-900 mb-8">{selectedWorker.hourlyRate.toLocaleString()} FCFA <span className="text-sm font-medium text-slate-400">/ heure</span></div>
               <div className="flex gap-4">
                 <button onClick={() => window.location.href = `tel:${selectedWorker.phone}`} className="flex-1 bg-slate-900 text-white py-5 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3"><i className="fas fa-phone-alt"></i> Appeler</button>
                 <button className="flex-1 bg-blue-700 text-white py-5 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-3"><i className="fas fa-comment"></i> WhatsApp</button>
               </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useMemo, useRef, useEffect } from 'react';
import { CATEGORIES, MOCK_WORKERS } from './constants';
import { MaintenanceWorker } from './types';
import { diagnoseIssue, refineLocation } from './services/geminiService';

declare var L: any; // Global Leaflet

const App: React.FC = () => {
  const [workers, setWorkers] = useState<MaintenanceWorker[]>(MOCK_WORKERS);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [cityQuery, setCityQuery] = useState('');
  const [aiLoading, setAiLoading] = useState(false);
  const [aiResult, setAiResult] = useState<{ category: string, explanation: string, urgency: string } | null>(null);
  const [selectedWorker, setSelectedWorker] = useState<MaintenanceWorker | null>(null);
  const [viewMode, setViewMode] = useState<'landing' | 'list' | 'map'>('landing');
  const [isProModalOpen, setIsProModalOpen] = useState(false);
  const [locationLoading, setLocationLoading] = useState(false);
  const [userLocation, setUserLocation] = useState<{ lat: number, lng: number } | null>(null);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const mapRef = useRef<any>(null);
  const mapContainerRef = useRef<HTMLDivElement>(null);
  const markersLayerRef = useRef<any>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [newWorker, setNewWorker] = useState({
    name: '',
    category: 'general',
    experience: '',
    hourlyRate: '',
    phone: '',
    skills: '',
    address: '',
    avatar: ''
  });

  const requestUserLocation = (silent: boolean = false) => {
    if (!silent) setLocationLoading(true);
    setErrorMessage(null);

    if ("geolocation" in navigator) {
      navigator.geolocation.getCurrentPosition(
        (position) => {
          const coords = { lat: position.coords.latitude, lng: position.coords.longitude };
          setUserLocation(coords);
          setLocationLoading(false);
          if (mapRef.current) {
            mapRef.current.flyTo([coords.lat, coords.lng], 15);
          }
          if (viewMode === 'landing') setViewMode('list');
        },
        (error) => {
          setLocationLoading(false);
          setErrorMessage("Accès localisation refusé. Veuillez saisir votre ville manuellement.");
          console.warn(error);
        },
        { enableHighAccuracy: true, timeout: 8000 }
      );
    } else {
      setErrorMessage("La géolocalisation n'est pas supportée par votre navigateur.");
      setLocationLoading(false);
    }
  };

  const filteredWorkers = useMemo(() => {
    return workers.filter(worker => {
      const matchesCategory = selectedCategory ? worker.category === selectedCategory : true;
      const matchesSearch = worker.name.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           worker.skills.some(s => s.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesCity = cityQuery ? worker.location.address.toLowerCase().includes(cityQuery.toLowerCase()) : true;
      return matchesCategory && matchesSearch && matchesCity;
    });
  }, [selectedCategory, searchQuery, cityQuery, workers]);

  useEffect(() => {
    if (viewMode === 'map' && mapContainerRef.current) {
      const timer = setTimeout(() => {
        if (!mapContainerRef.current) return;
        const center = userLocation || { lat: 4.0511, lng: 9.7679 }; // Douala par défaut
        if (!mapRef.current) {
          mapRef.current = L.map(mapContainerRef.current, { zoomControl: false }).setView([center.lat, center.lng], 13);
          L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
            attribution: '&copy; OpenStreetMap contributors'
          }).addTo(mapRef.current);
          L.control.zoom({ position: 'bottomright' }).addTo(mapRef.current);
          markersLayerRef.current = L.layerGroup().addTo(mapRef.current);
        }
        markersLayerRef.current.clearLayers();
        filteredWorkers.forEach(worker => {
          const icon = L.divIcon({
            className: 'worker-map-marker',
            html: `<img src="${worker.avatar}" class="marker-avatar" alt="">`,
            iconSize: [44, 44],
            iconAnchor: [22, 22]
          });
          const marker = L.marker([worker.location.lat, worker.location.lng], { icon }).addTo(markersLayerRef.current);
          marker.on('click', () => setSelectedWorker(worker));
        });
        if (userLocation) {
          const userIcon = L.divIcon({
            className: 'user-marker-wrapper',
            html: `<div class="user-marker-pulse"></div><div class="user-marker-core"></div>`,
            iconSize: [40, 40],
            iconAnchor: [20, 20]
          });
          L.marker([userLocation.lat, userLocation.lng], { icon: userIcon, zIndexOffset: 2000 }).addTo(markersLayerRef.current);
        }
      }, 100);
      return () => clearTimeout(timer);
    }
