          <button onClick={() => setViewMode('register')} className="bg-[#1e4ad8] text-white px-7 py-3 rounded-xl font-bold text-sm shadow-xl shadow-blue-100 hover:bg-blue-800 transition-all">Inscription</button>
        </div>
      </div>
    </nav>
  );

  const renderFooter = () => (
