            <a href="#" className="w-9 h-9 rounded-lg bg-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fab fa-facebook-f text-sm"></i></a>
            <a href="#" className="w-9 h-9 rounded-lg bg-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fab fa-twitter text-sm"></i></a>
            <a href="#" className="w-9 h-9 rounded-lg bg-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fab fa-instagram text-sm"></i></a>
            <a href="#" className="w-9 h-9 rounded-lg bg-slate-800 flex items-center justify-center text-slate-400 hover:text-white transition-all"><i className="fab fa-linkedin-in text-sm"></i></a>
          </div>
