        </div>
        <div>
          <h4 className="font-bold text-base mb-8">Contact</h4>
          <ul className="space-y-5 text-sm text-slate-400 font-medium">
            <li className="flex items-center gap-3"><i className="far fa-envelope text-orange-500"></i> contact@maintenanceconnect.com</li>
            <li className="flex items-center gap-3"><i className="fas fa-phone-alt text-orange-500"></i> +237 6 00 00 00 00</li>
            <li className="flex items-start gap-3"><i className="fas fa-map-marker-alt text-orange-500"></i> Bastos, Yaoundé, Cameroun</li>
          </ul>
        </div>
      </div>
      <div className="max-w-7xl mx-auto px-6 pt-10 border-t border-slate-800/50 text-center text-slate-500 text-xs font-semibold">
        © 2024 MaintenanceConnect. Tous droits réservés.
      </div>
    </footer>
  );

  const renderLogin = () => (
    <div className="min-h-screen bg-slate-50 flex flex-col">
      {renderHeader()}
      <div className="flex-1 flex items-center justify-center px-6 py-20">
        <div className="bg-white w-full max-w-md rounded-2xl shadow-xl border border-slate-100 p-10 lg:p-12 animate-in fade-in zoom-in-95 duration-300">
          <div className="text-center mb-10">
            <h1 className="text-3xl font-black text-slate-900 mb-2">Connexion</h1>
            <p className="text-slate-500 text-sm font-medium">Connectez-vous à votre compte MaintenanceConnect</p>
          </div>
          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-sm font-bold text-slate-900 ml-1">Email</label>
              <div className="relative">
                <i className="far fa-envelope absolute left-4 top-1/2 -translate-y-1/2 text-slate-300"></i>
                <input type="email" placeholder="votre@email.com" className="w-full pl-12 pr-4 py-3.5 bg-slate-50 border border-slate-200 rounded-xl outline-none focus:border-blue-600 focus:bg-white transition-all font-medium text-slate-700" />
