              </div>
            </div>
            <button onClick={() => setViewMode('landing')} className="w-full bg-[#1e4ad8] text-white py-4.5 rounded-xl font-bold flex items-center justify-center gap-3 hover:bg-blue-800 transition-all btn-shadow mt-4">
