          >
            Je cherche un pro
          </button>
          <button 
            onClick={() => setRegisterType('pro')} 
            className={`flex-1 py-4 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${registerType === 'pro' ? 'bg-white text-blue-700 shadow-md' : 'text-slate-400 hover:text-slate-600'}`}
          >
            Je suis un pro
          </button>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Nom complet</label>
            <input type="text" placeholder="Jean Dupont" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 text-slate-700 font-bold focus:border-[#1e4ad8] focus:bg-white outline-none transition-all" />
          </div>
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Téléphone (+237)</label>
            <input type="tel" placeholder="6XX XX XX XX" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 text-slate-700 font-bold focus:border-[#1e4ad8] focus:bg-white outline-none transition-all" />
          </div>
          <div className="md:col-span-2 space-y-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest ml-1">Email</label>
            <input type="email" placeholder="votre@email.com" className="w-full bg-slate-50 border-2 border-slate-100 rounded-2xl px-6 py-4 text-slate-700 font-bold focus:border-[#1e4ad8] focus:bg-white outline-none transition-all" />
          </div>
