                iconSize: [32, 32],
                iconAnchor: [16, 32]
            });
            L.marker([selectedWorker.location.lat, selectedWorker.location.lng], { icon: pinIcon }).addTo(detailMapRef.current);
         } else {
            detailMapRef.current.setView([selectedWorker.location.lat, selectedWorker.location.lng], 14);
