                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="bg-white rounded-[2rem] h-[650px] border border-slate-100 shadow-2xl overflow-hidden relative mb-20">
                     <div ref={mapContainerRef} className="w-full h-full"></div>
                  </div>
                )}
              </div>
              {renderFooter()}
            </>
          )}
        </main>
      )}
    </div>
  );
};

