                            <img src={worker.avatar} className="w-20 h-20 rounded-2xl object-cover shadow-lg border-2 border-white" alt={worker.name} />
                            <div className="text-right">
                              <div className="text-2xl font-black text-slate-900 leading-none">{worker.hourlyRate.toLocaleString()} <span className="text-[11px] text-slate-400 font-bold">FCFA</span></div>
                              <div className="text-orange-500 font-black text-[12px] mt-2 flex items-center justify-end gap-1"><i className="fas fa-star text-[10px]"></i> {worker.rating}</div>
                            </div>
                          </div>
                          <h4 className="text-xl font-black text-slate-900 mb-2 group-hover:text-blue-700 transition-colors">{worker.name}</h4>
                          <p className="text-slate-400 font-bold text-[11px] uppercase tracking-widest flex items-center gap-2 mb-10"><i className="fas fa-map-marker-alt text-blue-600"></i>{worker.location.address}</p>
                          <div className="pt-8 border-t border-slate-50 flex flex-wrap gap-2.5">{worker.skills.map((skill, idx) => (<span key={idx} className="px-4 py-2 bg-blue-50/50 text-blue-700 rounded-xl text-[10px] font-black uppercase tracking-wider">{skill}</span>))}</div>
                        </div>
                      </div>
                    ))}
                  </div>
                ) : (
                  <div className="bg-white rounded-[2.5rem] h-[650px] border-4 border-white shadow-2xl overflow-hidden relative mb-20">
                     <div ref={mapContainerRef} className="w-full h-full"></div>
                  </div>
                )}
              </div>
              {renderFooter()}
            </>
          )}
        </main>
      )}
    </div>
  );
};

